def _make_dynamic_bit_select_cont_lhs() -> Module:
    """assign x[idx] = a;"""
    return Module(
        "dynamic_bit_select_cont_lhs",
        ports=[
            Port("idx", PortDirection.INPUT, width=Range(Literal(2, width=32), Literal(0, width=32))),
            Port("a", PortDirection.INPUT),
            Port("x", PortDirection.OUTPUT, width=_w8()),
        ],
        nets=[
            Net("idx", NetKind.WIRE, width=Range(Literal(2, width=32), Literal(0, width=32))),
            Net("a", NetKind.WIRE),
            Net("x", NetKind.WIRE, width=_w8()),
        ],
        continuous_assigns=[
            ContinuousAssign(
                BitSelect(Identifier("x"), Identifier("idx")),
                Identifier("a"),
            ),
        ],
    )


def _make_dynamic_bit_select_combo_lhs() -> Module:
    """always @(*) begin y = 0; y[idx] = a; end"""
    mod = Module(
        "dynamic_bit_select_combo_lhs",
        ports=[
            Port("idx", PortDirection.INPUT, width=Range(Literal(2, width=32), Literal(0, width=32))),
            Port("a", PortDirection.INPUT),
            Port("y", PortDirection.OUTPUT, width=_w8()),
        ],
        nets=[
            Net("idx", NetKind.WIRE, width=Range(Literal(2, width=32), Literal(0, width=32))),
            Net("a", NetKind.WIRE),
        ],
        variables=[Variable("y", VariableKind.REG, width=_w8())],
    )
    mod.always_blocks = [
        AlwaysBlock(
            SeqBlock(
                [
                    BlockingAssign(Identifier("y"), Literal(0, width=8)),
                    BlockingAssign(BitSelect(Identifier("y"), Identifier("idx")), Identifier("a")),
                ]
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        )
    ]
    return mod


