def _make_wide_struct_signal_copy(mode: str) -> Module:
    """Transport-only direct whole packed-struct signal copy surface."""
    data_width = 65
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = [
        Port("in_bus", PortDirection.INPUT, width=_w(total_width)),
        Port("out_bus", PortDirection.OUTPUT, width=_w(total_width)),
    ]
    nets = [
        Net("in_bus", NetKind.WIRE, width=_w(total_width)),
        Net("out_bus", NetKind.WIRE, width=_w(total_width)),
    ]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_signal_copy_{mode}",
        ports=ports,
        nets=nets,
        variables=[
            Variable("src", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
            Variable("dst", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
        ],
    )
    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(Identifier("src"), Identifier("in_bus")),
            ContinuousAssign(Identifier("dst"), Identifier("src")),
            ContinuousAssign(Identifier("out_bus"), Identifier("dst")),
        ]
    elif mode == "combo":
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock(
                    [
                        BlockingAssign(Identifier("src"), Identifier("in_bus")),
                        BlockingAssign(Identifier("dst"), Identifier("src")),
                    ]
                ),
                sensitivity_type=SensitivityType.COMBINATIONAL,
            )
        ]
        mod.continuous_assigns = [ContinuousAssign(Identifier("out_bus"), Identifier("dst"))]
    else:
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([NonblockingAssign(Identifier("dst"), Identifier("src"))]),
                sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                sensitivity_type=SensitivityType.SEQUENTIAL,
            )
        ]
        mod.continuous_assigns = [
            ContinuousAssign(Identifier("src"), Identifier("in_bus")),
            ContinuousAssign(Identifier("out_bus"), Identifier("dst")),
        ]
    mod.typedefs = [td]
    return mod


