def _make_wide_struct_signal_field(mode: str) -> Module:
    """Write wide packed-struct signal fields directly in the requested assignment mode."""
    data_width = 65
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = [
        Port("in_data", PortDirection.INPUT, width=_w(data_width)),
        Port("in_valid", PortDirection.INPUT),
    ]
    nets = [
        Net("in_data", NetKind.WIRE, width=_w(data_width)),
        Net("in_valid", NetKind.WIRE),
    ]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_signal_field_{mode}",
        ports=ports,
        nets=nets,
        variables=[Variable("bus", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t")],
    )
    assigns = [
        BlockingAssign(Identifier("bus.data"), Identifier("in_data")),
        BlockingAssign(Identifier("bus.valid"), Identifier("in_valid")),
    ]
    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(Identifier("bus.data"), Identifier("in_data")),
            ContinuousAssign(Identifier("bus.valid"), Identifier("in_valid")),
        ]
    else:
        if mode == "seq":
            assigns = [
                NonblockingAssign(Identifier("bus.data"), Identifier("in_data")),
                NonblockingAssign(Identifier("bus.valid"), Identifier("in_valid")),
            ]
        sensitivity_list = [SensitivityEdge("posedge", Identifier("clk"))] if mode == "seq" else None
        sensitivity_type = SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock(assigns),
                sensitivity_list=sensitivity_list,
                sensitivity_type=sensitivity_type,
            )
        ]
    mod.typedefs = [td]
    return mod


