def _make_wide_struct_signal_field_concat(mode: str) -> Module:
    """Write a wide concat of packed-struct signal fields in the requested assignment mode."""
    data_width = 65
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = [Port("in_bus", PortDirection.INPUT, width=_w(total_width))]
    nets = [Net("in_bus", NetKind.WIRE, width=_w(total_width))]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_signal_field_concat_{mode}",
        ports=ports,
        nets=nets,
        variables=[Variable("bus", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t")],
    )
    lhs = Concatenation([Identifier("bus.data"), Identifier("bus.valid")])
    rhs = Identifier("in_bus")
    if mode == "cont":
        mod.continuous_assigns = [ContinuousAssign(lhs, rhs)]
    else:
        assign = NonblockingAssign(lhs, rhs) if mode == "seq" else BlockingAssign(lhs, rhs)
        sensitivity_list = [SensitivityEdge("posedge", Identifier("clk"))] if mode == "seq" else None
        sensitivity_type = SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([assign]),
                sensitivity_list=sensitivity_list,
                sensitivity_type=sensitivity_type,
            )
        ]
    mod.typedefs = [td]
    return mod


