def _make_wide_combo_add(width: int) -> Module:
    mod = Module(
        f"wide_combo_add_{width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("b", PortDirection.INPUT, width=_w(width)),
            Port("y", PortDirection.OUTPUT, width=_w(width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("b", NetKind.WIRE, width=_w(width)),
        ],
        variables=[Variable("y", VariableKind.REG, width=_w(width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(Identifier("y"), BinaryOp("+", Identifier("a"), Identifier("b"))),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        ),
    ]
    return mod


def _make_wide_seq_add(width: int) -> Module:
    """always @(posedge clk) q <= a + b; using a wide whole-signal NBA."""
    mod = Module(
        f"wide_seq_add_{width}",
        ports=[
            Port("clk", PortDirection.INPUT),
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("b", PortDirection.INPUT, width=_w(width)),
            Port("q", PortDirection.OUTPUT, width=_w(width)),
        ],
        nets=[
            Net("clk", NetKind.WIRE),
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("b", NetKind.WIRE, width=_w(width)),
        ],
        variables=[Variable("q", VariableKind.REG, width=_w(width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            NonblockingAssign(Identifier("q"), BinaryOp("+", Identifier("a"), Identifier("b"))),
            sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
            sensitivity_type=SensitivityType.SEQUENTIAL,
        ),
    ]
    return mod


def _make_wide_combo_add_const(width: int, literal_value: int, literal_width: int = 32) -> Module:
    """always @(*) y = a + CONST; using a wide whole-signal blocking assignment."""
    mod = Module(
        f"wide_combo_add_const_{width}_{literal_width}_{literal_value}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("y", PortDirection.OUTPUT, width=_w(width)),
        ],
        nets=[Net("a", NetKind.WIRE, width=_w(width))],
        variables=[Variable("y", VariableKind.REG, width=_w(width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(
                Identifier("y"), BinaryOp("+", Identifier("a"), Literal(literal_value, width=literal_width))
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        ),
    ]
    return mod


