    mod = Module(
        f"wide_combo_add_const_and_{width}_{literal_width}_{literal_value}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("b", PortDirection.INPUT, width=_w(width)),
            Port("y", PortDirection.OUTPUT, width=_w(width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("b", NetKind.WIRE, width=_w(width)),
        ],
        variables=[Variable("y", VariableKind.REG, width=_w(width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(
                Identifier("y"),
                BinaryOp(
                    "&", BinaryOp("+", Identifier("a"), Literal(literal_value, width=literal_width)), Identifier("b")
                ),
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        ),
    ]
    return mod


