def _make_wide_combo_range_pair_concat_shift(
    src_width: int,
    hi_msb: int,
    hi_lsb: int,
    lo_msb: int,
    lo_lsb: int,
    op: str,
    shift: int,
    dst_width: int | None = None,
) -> Module:
    """always @(*) y = {a[hi:lo], a[hi2:lo2]} << N / >> N; flat range-leaf concat shift blocking assignment."""
    total_width = (hi_msb - hi_lsb + 1) + (lo_msb - lo_lsb + 1)
    if dst_width is None:
        dst_width = total_width
    op_tag = {"<<": "shl", ">>": "shr"}[op]
    expr = Concatenation(
        [
            RangeSelect(Identifier("a"), Literal(hi_msb, width=32), Literal(hi_lsb, width=32)),
            RangeSelect(Identifier("a"), Literal(lo_msb, width=32), Literal(lo_lsb, width=32)),
        ]
    )
    mod = Module(
        f"wide_c_crp_{op_tag}_{src_width}_{hi_msb}_{hi_lsb}_{lo_msb}_{lo_lsb}_{dst_width}_{shift}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("y", PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[Net("a", NetKind.WIRE, width=_w(src_width))],
        variables=[Variable("y", VariableKind.REG, width=_w(dst_width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(Identifier("y"), BinaryOp(op, expr, Literal(shift, width=32))),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        ),
    ]
    return mod


