def _make_wide_dynamic_part_extract(
    src_width: int,
    part_width: int,
    dst_width: int | None = None,
    direction: str = "+:",
) -> Module:
    """assign y = a[base +/-: part_width]; constant-width dynamic part-select."""
    if dst_width is None:
        dst_width = part_width
    direction_tag = "plus" if direction == "+:" else "minus"
    return Module(
        f"wide_dynamic_part_extract_{src_width}_{part_width}_{dst_width}_{direction_tag}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("base", PortDirection.INPUT, width=_w8()),
            Port("y", PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("base", NetKind.WIRE, width=_w8()),
            Net("y", NetKind.WIRE, width=_w(dst_width)),
        ],
        continuous_assigns=[
            ContinuousAssign(
                Identifier("y"),
                PartSelect(Identifier("a"), Identifier("base"), Literal(part_width, width=32), direction),
            ),
        ],
    )


def _make_wide_combo_dynamic_part_extract(
    src_width: int,
    part_width: int,
    dst_width: int | None = None,
    direction: str = "+:",
) -> Module:
    """always @(*) y = a[base +/-: part_width]; constant-width wide combo dynamic part-select."""
    if dst_width is None:
        dst_width = part_width
    direction_tag = "plus" if direction == "+:" else "minus"
    mod = Module(
        f"wide_combo_dynamic_part_extract_{src_width}_{part_width}_{dst_width}_{direction_tag}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("base", PortDirection.INPUT, width=_w8()),
            Port("y", PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("base", NetKind.WIRE, width=_w8()),
        ],
        variables=[Variable("y", VariableKind.REG, width=_w(dst_width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(
                Identifier("y"),
                PartSelect(Identifier("a"), Identifier("base"), Literal(part_width, width=32), direction),
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        )
    ]
    return mod


def _make_wide_seq_dynamic_part_extract(
    src_width: int,
    part_width: int,
    dst_width: int | None = None,
    direction: str = "+:",
) -> Module:
    """always @(posedge clk) q <= a[base +/-: part_width]; constant-width wide seq dynamic part-select."""
    if dst_width is None:
        dst_width = part_width
    direction_tag = "plus" if direction == "+:" else "minus"
    mod = Module(
        f"wide_seq_dynamic_part_extract_{src_width}_{part_width}_{dst_width}_{direction_tag}",
        ports=[
            Port("clk", PortDirection.INPUT),
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("base", PortDirection.INPUT, width=_w8()),
            Port("q", PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            Net("clk", NetKind.WIRE),
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("base", NetKind.WIRE, width=_w8()),
        ],
        variables=[Variable("q", VariableKind.REG, width=_w(dst_width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            NonblockingAssign(
                Identifier("q"),
                PartSelect(Identifier("a"), Identifier("base"), Literal(part_width, width=32), direction),
            ),
            sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
            sensitivity_type=SensitivityType.SEQUENTIAL,
        )
    ]
    return mod


