def _make_wide_signed_core_shift_module(
    name_tag: str,
    src_width: int,
    *,
    mode: str,
    shift: int | None = None,
    shift_width: int = 8,
    dst_width: int | None = None,
    inner_op: str | None = None,
) -> Module:
    if dst_width is None:
        dst_width = src_width

    mode_tag = {"continuous": "b", "combo": "c", "seq": "s"}[mode]
    output_name = "q" if mode == "seq" else "y"
    ports = []
    nets = []
    if mode == "seq":
        ports.append(Port("clk", PortDirection.INPUT))
        nets.append(Net("clk", NetKind.WIRE))

    ports.append(Port("a", PortDirection.INPUT, width=_w(src_width)))
    nets.append(Net("a", NetKind.WIRE, width=_w(src_width)))
    if inner_op is not None:
        ports.append(Port("b", PortDirection.INPUT, width=_w(src_width)))
        nets.append(Net("b", NetKind.WIRE, width=_w(src_width)))
    if shift is None:
        shift_range = Range(Literal(shift_width - 1, width=32), Literal(0, width=32))
        ports.append(Port("sh", PortDirection.INPUT, width=shift_range))
        nets.append(Net("sh", NetKind.WIRE, width=shift_range))
    ports.append(Port(output_name, PortDirection.OUTPUT, width=_w(dst_width)))
    if mode == "continuous":
        nets.append(Net(output_name, NetKind.WIRE, width=_w(dst_width)))

    signed_arg: Expression = Identifier("a")
    if inner_op is not None:
        signed_arg = BinaryOp(inner_op, Identifier("a"), Identifier("b"))
    shift_expr: Expression = Identifier("sh") if shift is None else Literal(shift, width=32)
    rhs = BinaryOp(">>>", FunctionCall("$signed", [signed_arg], is_system=True), shift_expr)

    module_name = f"wide_{mode_tag}_{name_tag}_{src_width}_{shift_width if shift is None else shift}_{dst_width}"
    if mode == "continuous":
        return Module(
            module_name, ports=ports, nets=nets, continuous_assigns=[ContinuousAssign(Identifier(output_name), rhs)]
        )

    assign: BlockingAssign | NonblockingAssign = BlockingAssign(Identifier(output_name), rhs)
    sensitivity_type = SensitivityType.COMBINATIONAL
    if mode == "seq":
        assign = NonblockingAssign(Identifier(output_name), rhs)
        sensitivity_type = SensitivityType.SEQUENTIAL

    mod = Module(
        module_name,
        ports=ports,
        nets=nets,
        variables=[Variable(output_name, VariableKind.REG, width=_w(dst_width))],
    )
    always_kwargs = {"sensitivity_type": sensitivity_type}
    if mode == "seq":
        always_kwargs["sensitivity_list"] = [SensitivityEdge("posedge", Identifier("clk"))]
    mod.always_blocks = [AlwaysBlock(assign, **always_kwargs)]
    return mod


def _make_wide_combo_signed_shift_binop(src_width: int, shift: int, dst_width: int | None = None) -> Module:
    """always @(*) y = $signed(a) >>> N; simple whole-signal wide signed combo regression."""
    return _make_wide_signed_core_shift_module(
        "signed_shift", src_width, mode="combo", shift=shift, dst_width=dst_width
    )


