def _make_wide_generic_and_or_signal_tree_binop(
    src_width: int,
    dst_width: int | None = None,
) -> Module:
    """assign y = (a & b) | c; generic wide mixed-tree regression."""
    return _make_wide_generic_mixed_binop_signal_tree_by_mode(src_width, "&", "|", "b", "and", "or", dst_width)


def _make_wide_generic_mixed_binop_signal_tree_by_mode(
    src_width: int,
    inner_op: str,
    outer_op: str,
    mode_tag: str,
    inner_name_tag: str,
    outer_name_tag: str,
    dst_width: int | None = None,
    *,
    tree_on_left: bool = True,
) -> Module:
    if dst_width is None:
        dst_width = src_width
    output_name = "q" if mode_tag == "s" else "y"
    inner_expr = BinaryOp(inner_op, Identifier("a"), Identifier("b"))
    expr = (
        BinaryOp(outer_op, inner_expr, Identifier("c"))
        if tree_on_left
        else BinaryOp(outer_op, Identifier("c"), inner_expr)
    )
    side_tag = "lhs" if tree_on_left else "rhs"
    mod = Module(
        f"wide_{mode_tag}_sig_mixed_{inner_name_tag}_{outer_name_tag}_{side_tag}_{src_width}_{dst_width}",
        ports=[
            *([Port("clk", PortDirection.INPUT)] if mode_tag == "s" else []),
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("b", PortDirection.INPUT, width=_w(src_width)),
            Port("c", PortDirection.INPUT, width=_w(src_width)),
            Port(output_name, PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            *([Net("clk", NetKind.WIRE)] if mode_tag == "s" else []),
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("b", NetKind.WIRE, width=_w(src_width)),
            Net("c", NetKind.WIRE, width=_w(src_width)),
            *([Net(output_name, NetKind.WIRE, width=_w(dst_width))] if mode_tag == "b" else []),
        ],
        variables=[Variable(output_name, VariableKind.REG, width=_w(dst_width))] if mode_tag != "b" else [],
        continuous_assigns=[ContinuousAssign(Identifier(output_name), expr)] if mode_tag == "b" else [],
    )
    if mode_tag != "b":
        assign: BlockingAssign | NonblockingAssign
        if mode_tag == "s":
            assign = NonblockingAssign(Identifier(output_name), expr)
        else:
            assign = BlockingAssign(Identifier(output_name), expr)
        always_kwargs = {
            "sensitivity_type": SensitivityType.SEQUENTIAL if mode_tag == "s" else SensitivityType.COMBINATIONAL
        }
        if mode_tag == "s":
            always_kwargs["sensitivity_list"] = [SensitivityEdge("posedge", Identifier("clk"))]
        mod.always_blocks = [AlwaysBlock(assign, **always_kwargs)]
    return mod


def _make_wide_generic_const_binop_signal_tree_by_mode(
    src_width: int,
    inner_op: str,
    outer_op: str,
    mode_tag: str,
    inner_name_tag: str,
    outer_name_tag: str,
    literal_value: int,
    literal_width: int = 32,
    dst_width: int | None = None,
    *,
    tree_on_left: bool = True,
    literal_on_left: bool = False,
) -> Module:
    if dst_width is None:
        dst_width = src_width
    output_name = "q" if mode_tag == "s" else "y"
    literal_expr = Literal(literal_value, width=literal_width)
    inner_expr = (
        BinaryOp(inner_op, literal_expr, Identifier("a"))
        if literal_on_left
        else BinaryOp(inner_op, Identifier("a"), literal_expr)
    )
    expr = (
        BinaryOp(outer_op, inner_expr, Identifier("c"))
        if tree_on_left
        else BinaryOp(outer_op, Identifier("c"), inner_expr)
    )
    side_tag = "lhs" if tree_on_left else "rhs"
    literal_side_tag = "constlhs" if literal_on_left else "constrhs"
    mod = Module(
        f"wide_{mode_tag}_sig_const_{inner_name_tag}_{outer_name_tag}_{side_tag}_{literal_side_tag}_{src_width}_{dst_width}_{literal_width}_{literal_value}",
        ports=[
            *([Port("clk", PortDirection.INPUT)] if mode_tag == "s" else []),
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("c", PortDirection.INPUT, width=_w(src_width)),
            Port(output_name, PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            *([Net("clk", NetKind.WIRE)] if mode_tag == "s" else []),
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("c", NetKind.WIRE, width=_w(src_width)),
            *([Net(output_name, NetKind.WIRE, width=_w(dst_width))] if mode_tag == "b" else []),
        ],
        variables=[Variable(output_name, VariableKind.REG, width=_w(dst_width))] if mode_tag != "b" else [],
        continuous_assigns=[ContinuousAssign(Identifier(output_name), expr)] if mode_tag == "b" else [],
    )
    if mode_tag != "b":
        assign: BlockingAssign | NonblockingAssign
        if mode_tag == "s":
            assign = NonblockingAssign(Identifier(output_name), expr)
        else:
            assign = BlockingAssign(Identifier(output_name), expr)
        always_kwargs = {
            "sensitivity_type": SensitivityType.SEQUENTIAL if mode_tag == "s" else SensitivityType.COMBINATIONAL
        }
        if mode_tag == "s":
            always_kwargs["sensitivity_list"] = [SensitivityEdge("posedge", Identifier("clk"))]
