def _make_wide_generic_ternary_signal_tree_by_mode(
    width: int,
    op: str,
    mode_tag: str,
    name_tag: str,
    dst_width: int | None = None,
    *,
    tree_on_left: bool = True,
) -> Module:
    if dst_width is None:
        dst_width = width
    output_name = "q" if mode_tag == "s" else "y"
    ternary_expr = TernaryOp(Identifier("sel"), Identifier("a"), Identifier("b"))
    expr = BinaryOp(op, ternary_expr, Identifier("c")) if tree_on_left else BinaryOp(op, Identifier("c"), ternary_expr)
    side_tag = "lhs" if tree_on_left else "rhs"
    mod = Module(
        f"wide_{mode_tag}_sig_ternary_{name_tag}_{side_tag}_{width}_{dst_width}",
        ports=[
            *([Port("clk", PortDirection.INPUT)] if mode_tag == "s" else []),
            Port("sel", PortDirection.INPUT),
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("b", PortDirection.INPUT, width=_w(width)),
            Port("c", PortDirection.INPUT, width=_w(width)),
            Port(output_name, PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            *([Net("clk", NetKind.WIRE)] if mode_tag == "s" else []),
            Net("sel", NetKind.WIRE),
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("b", NetKind.WIRE, width=_w(width)),
            Net("c", NetKind.WIRE, width=_w(width)),
            *([Net(output_name, NetKind.WIRE, width=_w(dst_width))] if mode_tag == "b" else []),
        ],
        variables=[Variable(output_name, VariableKind.REG, width=_w(dst_width))] if mode_tag != "b" else [],
        continuous_assigns=[ContinuousAssign(Identifier(output_name), expr)] if mode_tag == "b" else [],
    )
    if mode_tag != "b":
        assign: BlockingAssign | NonblockingAssign
        if mode_tag == "s":
            assign = NonblockingAssign(Identifier(output_name), expr)
        else:
            assign = BlockingAssign(Identifier(output_name), expr)
        always_kwargs = {
            "sensitivity_type": SensitivityType.SEQUENTIAL if mode_tag == "s" else SensitivityType.COMBINATIONAL
        }
        if mode_tag == "s":
            always_kwargs["sensitivity_list"] = [SensitivityEdge("posedge", Identifier("clk"))]
        mod.always_blocks = [AlwaysBlock(assign, **always_kwargs)]
    return mod


def _make_wide_ternary_slice_signal_tree(mode: str, width: int = 129, msb: int = 128, lsb: int = 64) -> Module:
    """Wide ternary that selects between >64-bit source slices."""
    dst_width = msb - lsb + 1
    output_name = "q" if mode == "seq" else "y"
    expr = TernaryOp(
        Identifier("sel"),
        RangeSelect(Identifier("a"), Literal(msb, width=32), Literal(lsb, width=32)),
        RangeSelect(Identifier("b"), Literal(msb, width=32), Literal(lsb, width=32)),
    )
    mod = Module(
        f"wide_{mode}_sig_ternary_slice_{width}_{dst_width}_{msb}_{lsb}",
        ports=[
            *([Port("clk", PortDirection.INPUT)] if mode == "seq" else []),
            Port("sel", PortDirection.INPUT),
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("b", PortDirection.INPUT, width=_w(width)),
            Port(output_name, PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            *([Net("clk", NetKind.WIRE)] if mode == "seq" else []),
            Net("sel", NetKind.WIRE),
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("b", NetKind.WIRE, width=_w(width)),
            *([Net(output_name, NetKind.WIRE, width=_w(dst_width))] if mode == "cont" else []),
        ],
        variables=[Variable(output_name, VariableKind.REG, width=_w(dst_width))] if mode != "cont" else [],
        continuous_assigns=[ContinuousAssign(Identifier(output_name), expr)] if mode == "cont" else [],
    )
    if mode != "cont":
        assign: BlockingAssign | NonblockingAssign
        if mode == "seq":
            assign = NonblockingAssign(Identifier(output_name), expr)
        else:
            assign = BlockingAssign(Identifier(output_name), expr)
        always_kwargs = {
            "sensitivity_type": SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        }
        if mode == "seq":
            always_kwargs["sensitivity_list"] = [SensitivityEdge("posedge", Identifier("clk"))]
