def _make_wide_generic_part_signal_tree_by_mode(
    src_width: int,
    part_width: int,
    op: str,
    mode_tag: str,
    name_tag: str,
    dst_width: int | None = None,
    direction: str = "+:",
    *,
    tree_on_left: bool = True,
) -> Module:
    if dst_width is None:
        dst_width = part_width
    direction_tag = "plus" if direction == "+:" else "minus"
    output_name = "q" if mode_tag == "s" else "y"
    part_expr = PartSelect(Identifier("a"), Identifier("base"), Literal(part_width, width=32), direction)
    expr = BinaryOp(op, part_expr, Identifier("b")) if tree_on_left else BinaryOp(op, Identifier("b"), part_expr)
    side_tag = "lhs" if tree_on_left else "rhs"
    mod = Module(
        f"wide_{mode_tag}_sig_part_{name_tag}_{side_tag}_{src_width}_{part_width}_{dst_width}_{direction_tag}",
        ports=[
            *([Port("clk", PortDirection.INPUT)] if mode_tag == "s" else []),
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("base", PortDirection.INPUT, width=Range(Literal(7, width=32), Literal(0, width=32))),
            Port("b", PortDirection.INPUT, width=_w(part_width)),
            Port(output_name, PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            *([Net("clk", NetKind.WIRE)] if mode_tag == "s" else []),
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("base", NetKind.WIRE, width=Range(Literal(7, width=32), Literal(0, width=32))),
            Net("b", NetKind.WIRE, width=_w(part_width)),
            *([Net(output_name, NetKind.WIRE, width=_w(dst_width))] if mode_tag == "b" else []),
        ],
        variables=[Variable(output_name, VariableKind.REG, width=_w(dst_width))] if mode_tag != "b" else [],
        continuous_assigns=([ContinuousAssign(Identifier(output_name), expr)] if mode_tag == "b" else []),
    )
    if mode_tag != "b":
        assign: BlockingAssign | NonblockingAssign
        if mode_tag == "s":
            assign = NonblockingAssign(Identifier(output_name), expr)
        else:
            assign = BlockingAssign(Identifier(output_name), expr)
        always_kwargs = {
            "sensitivity_type": SensitivityType.SEQUENTIAL if mode_tag == "s" else SensitivityType.COMBINATIONAL
        }
        if mode_tag == "s":
            always_kwargs["sensitivity_list"] = [SensitivityEdge("posedge", Identifier("clk"))]
        mod.always_blocks = [AlwaysBlock(assign, **always_kwargs)]
    return mod


