    if dst_width is None:
        dst_width = width
    out_and = "q_and" if mode_tag == "s" else "y_and"
    out_add = "q_add" if mode_tag == "s" else "y_add"
    ternary_expr = TernaryOp(Identifier("sel"), Identifier("a"), Identifier("b"))
    expr_and = (
        BinaryOp("&", ternary_expr, Identifier("c")) if tree_on_left else BinaryOp("&", Identifier("c"), ternary_expr)
    )
    expr_add = (
        BinaryOp("+", ternary_expr, Identifier("c")) if tree_on_left else BinaryOp("+", Identifier("c"), ternary_expr)
    )
    side_tag = "lhs" if tree_on_left else "rhs"
