            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("b", PortDirection.INPUT, width=_w(width)),
            Port("c", PortDirection.INPUT, width=_w(width)),
            Port(out_and, PortDirection.OUTPUT, width=_w(dst_width)),
