def _make_wide_seq_generic_range_or_signal_tree(
    src_width: int,
    msb: int,
    lsb: int,
    dst_width: int | None = None,
    *,
    tree_on_left: bool = True,
) -> Module:
    """always @(posedge clk) q <= a[msb:lsb] | b; wide generic range-select NBA regression."""
    sel_width = msb - lsb + 1
    if dst_width is None:
        dst_width = sel_width
    range_expr = RangeSelect(Identifier("a"), Literal(msb, width=32), Literal(lsb, width=32))
    expr = BinaryOp("|", range_expr, Identifier("b")) if tree_on_left else BinaryOp("|", Identifier("b"), range_expr)
    side_tag = "lhs" if tree_on_left else "rhs"
    mod = Module(
        f"wide_s_sig_range_or_{side_tag}_{src_width}_{msb}_{lsb}_{dst_width}",
        ports=[
            Port("clk", PortDirection.INPUT),
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("b", PortDirection.INPUT, width=_w(sel_width)),
            Port("q", PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            Net("clk", NetKind.WIRE),
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("b", NetKind.WIRE, width=_w(sel_width)),
        ],
        variables=[Variable("q", VariableKind.REG, width=_w(dst_width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            NonblockingAssign(Identifier("q"), expr),
            sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
            sensitivity_type=SensitivityType.SEQUENTIAL,
        ),
    ]
    return mod


