def _make_wide_generic_concat_or_signal_tree(
    hi_width: int,
    lo_width: int,
    dst_width: int | None = None,
    *,
    tree_on_left: bool = True,
) -> Module:
    """assign y = {hi, lo} | c; wide generic concat-leaf regression."""
    total_width = hi_width + lo_width
    if dst_width is None:
        dst_width = total_width
    concat_expr = Concatenation([Identifier("hi"), Identifier("lo")])
    expr = BinaryOp("|", concat_expr, Identifier("c")) if tree_on_left else BinaryOp("|", Identifier("c"), concat_expr)
    side_tag = "lhs" if tree_on_left else "rhs"
    return Module(
        f"wide_b_sig_concat_or_{side_tag}_{hi_width}_{lo_width}_{dst_width}",
        ports=[
            Port("hi", PortDirection.INPUT, width=_w(hi_width)),
            Port("lo", PortDirection.INPUT, width=_w(lo_width)),
            Port("c", PortDirection.INPUT, width=_w(total_width)),
            Port("y", PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            Net("hi", NetKind.WIRE, width=_w(hi_width)),
            Net("lo", NetKind.WIRE, width=_w(lo_width)),
            Net("c", NetKind.WIRE, width=_w(total_width)),
            Net("y", NetKind.WIRE, width=_w(dst_width)),
        ],
        continuous_assigns=[
            ContinuousAssign(
                Identifier("y"),
                expr,
            ),
        ],
    )


