def _make_wide_signed_shift_var_binop(src_width: int, shift_width: int = 8, dst_width: int | None = None) -> Module:
    """assign y = $signed(a) >>> sh; simple whole-signal wide signed variable shift regression."""
    if dst_width is None:
        dst_width = src_width
    return Module(
        f"wide_signed_shift_var_{src_width}_{shift_width}_{dst_width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("sh", PortDirection.INPUT, width=Range(Literal(shift_width - 1, width=32), Literal(0, width=32))),
            Port("y", PortDirection.OUTPUT, width=_w(dst_width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("sh", NetKind.WIRE, width=Range(Literal(shift_width - 1, width=32), Literal(0, width=32))),
            Net("y", NetKind.WIRE, width=_w(dst_width)),
        ],
        continuous_assigns=[
            ContinuousAssign(
                Identifier("y"),
                BinaryOp(">>>", FunctionCall("$signed", [Identifier("a")], is_system=True), Identifier("sh")),
            ),
        ],
    )


