    @pytest.mark.parametrize("width", [65, 129])
    def test_wide_seq_nba_passthrough_cross_engine(self, width):
        value = (1 << (width - 1)) | 0x0F0F
        results = {}
        for eng in ["reference", "vm", "compiled"]:
            sim = Simulator(_make_wide_seq_passthrough(width), engine=eng)
            sim.drive("d", Value(value, width=width))
            sim.drive("q", Value(0, width=width))
            clk = Clock(sim.signal("clk"), period=10)
            sim.fork(clk)
            sim._schedule_clock_events(clk, 40)
            for _ in range(2):
                sim.run_step()
            results[eng] = sim.read("q")

        ref = Value(value, width=width)
        assert results["reference"] == ref
        assert results["compiled"] == results["reference"]
        assert results["vm"] == results["reference"]

    @pytest.mark.parametrize(
        ("src_width", "count", "value"),
        [
            (16, 5, 0x3CC3),
            (65, 2, (1 << 64) | 0x1111222233334444),
        ],
    )
    def test_wide_seq_nba_repeat_cross_engine(self, src_width, count, value):
        results = {}
        for eng in ["reference", "vm", "compiled"]:
            sim = Simulator(_make_wide_seq_repeat(src_width, count), engine=eng)
            sim.drive("a", Value(value, width=src_width))
            sim.drive("q", Value(0, width=src_width * count))
            clk = Clock(sim.signal("clk"), period=10)
            sim.fork(clk)
            sim._schedule_clock_events(clk, 40)
            for _ in range(2):
                sim.run_step()
            results[eng] = sim.read("q")

        ref = self._repeat_value(value, src_width, count)
        assert results["reference"] == ref
        for eng in ["vm", "compiled"]:
            assert results[eng] == ref, f"{eng}: {results[eng]} != {ref}"

    @pytest.mark.parametrize("width", [65, 129])
    def test_wide_seq_nba_literal_cross_engine(self, width):
        value = (1 << (width - 1)) | 0x0F0F
        results = {}
        for eng in ["reference", "vm", "compiled"]:
            sim = Simulator(_make_wide_seq_literal(width, value), engine=eng)
            sim.drive("q", Value(0, width=width))
            clk = Clock(sim.signal("clk"), period=10)
