    @pytest.mark.parametrize(
        ("builder_name", "needs_clock"),
        [
            ("_make_wide_struct_mem_field_cont", False),
            ("_make_wide_struct_mem_field_combo", False),
            ("_make_wide_struct_mem_field_seq", True),
        ],
    )
    def test_transport_only_mode_keeps_wide_struct_memory_field(self, monkeypatch, builder_name, needs_clock):
        monkeypatch.setenv("VERILOG_TOOLS_COMPILED_WIDE_TRANSPORT_ONLY", "1")

        builder = globals()[builder_name]
        data_value = (1 << 64) | 0x2468ACE
        data_mask = 0x20
        valid_value = 1
        valid_mask = 1
        results = {}
        for eng in ["reference", "vm", "compiled"]:
            sim = Simulator(builder(), engine=eng)
            sim.drive("addr", Value(1, width=1))
            sim.drive("in_data", Value(data_value, width=65, mask=data_mask))
            sim.drive("in_valid", Value(valid_value, width=1, mask=valid_mask))
            if needs_clock:
                clk = Clock(sim.signal("clk"), period=10)
                sim.fork(clk)
                sim._schedule_clock_events(clk, 40)
                for _ in range(2):
                    sim.run_step()
            else:
                sim.run(max_time=0)
            results[eng] = sim.read("mem[1]")

        expected_value = ((data_value & ~data_mask) << 1) | (valid_value & ~valid_mask)
        expected_mask = (data_mask << 1) | valid_mask
        expected = Value(expected_value, width=66, mask=expected_mask)
        assert results["reference"] == expected
        assert results["compiled"] == results["reference"]
        assert results["vm"] == results["reference"]

