    @pytest.mark.parametrize(
        ("builder_name", "needs_clock"),
        [
            ("_make_wide_struct_whole_mem_copy_combo", False),
            ("_make_wide_struct_whole_mem_copy_seq", True),
        ],
    )
    def test_transport_only_mode_keeps_wide_struct_whole_memory_copy(self, monkeypatch, builder_name, needs_clock):
        monkeypatch.setenv("VERILOG_TOOLS_COMPILED_WIDE_TRANSPORT_ONLY", "1")

        builder = globals()[builder_name]
        src0 = Value((((1 << 64) | 0x12345678) << 1) | 1, width=66, mask=(1 << 9) | 1)
        src1 = Value((0x0FEDCBA987654321 << 1), width=66, mask=1 << 17)
        results = {}
        for eng in ["reference", "vm", "compiled"]:
            sim = Simulator(builder(), engine=eng)
            sim.drive("src[0]", src0)
            sim.drive("src[1]", src1)
            if needs_clock:
                clk = Clock(sim.signal("clk"), period=10)
                sim.fork(clk)
                sim._schedule_clock_events(clk, 40)
                for _ in range(2):
                    sim.run_step()
            else:
                sim.run(max_time=0)
            results[eng] = {
                "out0": sim.read("out0"),
                "out1": sim.read("out1"),
                "dst[0]": sim.read("dst[0]"),
                "dst[1]": sim.read("dst[1]"),
            }

        expected_result = {"out0": src0, "out1": src1, "dst[0]": src0, "dst[1]": src1}
        assert results["reference"] == expected_result
        assert results["compiled"] == results["reference"]
        assert results["vm"] == results["reference"]

