def _make_struct_mem_field_part(mode: str) -> Module:
    """Write a dynamic part-select of mem[addr].data in the requested assignment mode."""
    st = StructType(
        [
            StructField("data", "logic", width=_w8()),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("bus_t", struct_type=st)
    ports = [
        Port("addr", PortDirection.INPUT, width=_w(1)),
        Port("base", PortDirection.INPUT, width=_w(3)),
        Port("in_bits", PortDirection.INPUT, width=_w(2)),
    ]
    nets = [
        Net("addr", NetKind.WIRE, width=_w(1)),
        Net("base", NetKind.WIRE, width=_w(3)),
        Net("in_bits", NetKind.WIRE, width=_w(2)),
    ]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"struct_mem_field_part_{mode}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "mem",
                VariableKind.REG,
                width=_w(9),
                type_name="bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )
    lhs = PartSelect(Identifier("mem[addr].data"), Identifier("base"), Literal(2, width=32), "+:")
    rhs = Identifier("in_bits")
    if mode == "cont":
        mod.continuous_assigns = [ContinuousAssign(lhs, rhs)]
    else:
        assign = NonblockingAssign(lhs, rhs) if mode == "seq" else BlockingAssign(lhs, rhs)
        sensitivity_list = [SensitivityEdge("posedge", Identifier("clk"))] if mode == "seq" else None
        sensitivity_type = SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([assign]) if mode != "seq" else SeqBlock([assign]),
                sensitivity_list=sensitivity_list,
                sensitivity_type=sensitivity_type,
            )
        ]
    mod.typedefs = [td]
    return mod


def _make_struct_mem_field_part_cont() -> Module:
    return _make_struct_mem_field_part("cont")


