def _make_wide_struct_mem_field(mode: str) -> Module:
    """Write wide packed-struct memory fields in the requested assignment mode."""
    data_width = 65
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = [
        Port("addr", PortDirection.INPUT, width=_w(1)),
        Port("in_data", PortDirection.INPUT, width=_w(data_width)),
        Port("in_valid", PortDirection.INPUT),
    ]
    nets = [
        Net("addr", NetKind.WIRE, width=_w(1)),
        Net("in_data", NetKind.WIRE, width=_w(data_width)),
        Net("in_valid", NetKind.WIRE),
    ]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_mem_field_{mode}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "mem",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )
    assigns = [
        BlockingAssign(Identifier("mem[addr].data"), Identifier("in_data")),
        BlockingAssign(Identifier("mem[addr].valid"), Identifier("in_valid")),
    ]
    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(Identifier("mem[addr].data"), Identifier("in_data")),
            ContinuousAssign(Identifier("mem[addr].valid"), Identifier("in_valid")),
        ]
    else:
        if mode == "seq":
            assigns = [
                NonblockingAssign(Identifier("mem[addr].data"), Identifier("in_data")),
                NonblockingAssign(Identifier("mem[addr].valid"), Identifier("in_valid")),
            ]
        sensitivity_list = [SensitivityEdge("posedge", Identifier("clk"))] if mode == "seq" else None
        sensitivity_type = SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock(assigns),
                sensitivity_list=sensitivity_list,
                sensitivity_type=sensitivity_type,
            )
        ]
    mod.typedefs = [td]
    return mod


def _make_wide_struct_mem_field_cont() -> Module:
    return _make_wide_struct_mem_field("cont")


