def _make_wide_struct_mem_to_signal_field_copy(mode: str, *, concat: bool = False) -> Module:
    """Copy packed-struct memory fields into a packed-struct signal and read it back."""
    data_width = 65
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = [
        Port("in_bus", PortDirection.INPUT, width=_w(total_width)),
        Port("out_bus", PortDirection.OUTPUT, width=_w(total_width)),
    ]
    nets = [
        Net("in_bus", NetKind.WIRE, width=_w(total_width)),
        Net("out_bus", NetKind.WIRE, width=_w(total_width)),
    ]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_mem_to_signal_field{'_concat' if concat else ''}_copy_{mode}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "src",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
            Variable("dst", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
        ],
    )
    src1 = BitSelect(Identifier("src"), Literal(1, width=32))
    if concat:
        dst_lhs = Concatenation([Identifier("dst.data"), Identifier("dst.valid")])
        src_rhs = Concatenation([Identifier("src[1].data"), Identifier("src[1].valid")])
        if mode == "cont":
            mod.continuous_assigns = [
                ContinuousAssign(src1, Identifier("in_bus")),
                ContinuousAssign(dst_lhs, src_rhs),
                ContinuousAssign(Identifier("out_bus"), Identifier("dst")),
            ]
        elif mode == "combo":
            mod.always_blocks = [
                AlwaysBlock(
                    SeqBlock([BlockingAssign(src1, Identifier("in_bus")), BlockingAssign(dst_lhs, src_rhs)]),
                    sensitivity_type=SensitivityType.COMBINATIONAL,
                )
            ]
            mod.continuous_assigns = [ContinuousAssign(Identifier("out_bus"), Identifier("dst"))]
        else:
            mod.always_blocks = [
                AlwaysBlock(
                    SeqBlock([NonblockingAssign(dst_lhs, src_rhs)]),
                    sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                    sensitivity_type=SensitivityType.SEQUENTIAL,
                )
            ]
            mod.continuous_assigns = [
                ContinuousAssign(src1, Identifier("in_bus")),
                ContinuousAssign(Identifier("out_bus"), Identifier("dst")),
            ]
    else:
        if mode == "cont":
            mod.continuous_assigns = [
                ContinuousAssign(src1, Identifier("in_bus")),
                ContinuousAssign(Identifier("dst.data"), Identifier("src[1].data")),
                ContinuousAssign(Identifier("dst.valid"), Identifier("src[1].valid")),
                ContinuousAssign(Identifier("out_bus"), Identifier("dst")),
            ]
        elif mode == "combo":
            mod.always_blocks = [
                AlwaysBlock(
                    SeqBlock(
                        [
                            BlockingAssign(src1, Identifier("in_bus")),
                            BlockingAssign(Identifier("dst.data"), Identifier("src[1].data")),
                            BlockingAssign(Identifier("dst.valid"), Identifier("src[1].valid")),
                        ]
                    ),
                    sensitivity_type=SensitivityType.COMBINATIONAL,
                )
            ]
            mod.continuous_assigns = [ContinuousAssign(Identifier("out_bus"), Identifier("dst"))]
        else:
            mod.always_blocks = [
                AlwaysBlock(
                    SeqBlock(
                        [
                            NonblockingAssign(Identifier("dst.data"), Identifier("src[1].data")),
                            NonblockingAssign(Identifier("dst.valid"), Identifier("src[1].valid")),
                        ]
                    ),
                    sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                    sensitivity_type=SensitivityType.SEQUENTIAL,
                )
            ]
            mod.continuous_assigns = [
                ContinuousAssign(src1, Identifier("in_bus")),
                ContinuousAssign(Identifier("out_bus"), Identifier("dst")),
            ]
    mod.typedefs = [td]
    return mod


