def _make_wide_struct_mem_to_signal_field_selector_copy(
    mode: str,
    selector_kind: str,
    *,
    dynamic: bool = False,
    direction: str = "+:",
    wide: bool = False,
    concat: bool = False,
) -> Module:
    """Copy packed-struct memory-field selectors into a packed-struct signal and read them back."""
    data_width = 129 if wide else 65
    select_width = 65 if wide else (1 if selector_kind == "bit" else (3 if concat else 2))
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    if selector_kind == "bit" and not concat:
        ports = [Port("in_bit", PortDirection.INPUT), Port("out_bits", PortDirection.OUTPUT)]
        nets = [Net("in_bit", NetKind.WIRE), Net("out_bits", NetKind.WIRE)]
    else:
        io_width = select_width + 1 if concat else select_width
        ports = [
            Port("in_bits", PortDirection.INPUT, width=_w(io_width)),
            Port("out_bits", PortDirection.OUTPUT, width=_w(io_width)),
        ]
        nets = [
            Net("in_bits", NetKind.WIRE, width=_w(io_width)),
            Net("out_bits", NetKind.WIRE, width=_w(io_width)),
        ]
    if selector_kind == "range" and dynamic:
        sel_width = 8 if wide else 7
        ports.extend(
            [
                Port("msb", PortDirection.INPUT, width=_w(sel_width)),
                Port("lsb", PortDirection.INPUT, width=_w(sel_width)),
            ]
        )
        nets.extend([Net("msb", NetKind.WIRE, width=_w(sel_width)), Net("lsb", NetKind.WIRE, width=_w(sel_width))])
    if selector_kind == "part" and dynamic:
        sel_width = 8 if wide else 7
        ports.append(Port("base", PortDirection.INPUT, width=_w(sel_width)))
        nets.append(Net("base", NetKind.WIRE, width=_w(sel_width)))
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_mem_to_signal_field{'_concat' if concat else ''}{'_wide' if wide else ''}_selector_copy_{selector_kind}_{mode}_{dynamic}_{direction.replace(':', '_')}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "src",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
            Variable("dst", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
        ],
    )

    def _selector(target_name: str):
        target = Identifier(target_name)
        if selector_kind == "bit":
            return BitSelect(target, Literal(128 if wide else 64, width=32))
        if selector_kind == "range":
            return RangeSelect(
                target,
                Identifier("msb") if dynamic else Literal(128 if wide else 64, width=32),
                Identifier("lsb") if dynamic else Literal(64 if wide else 63 if not concat else 62, width=32),
            )
        return PartSelect(
            target,
            Identifier("base")
            if dynamic
            else Literal(64 if direction == "+:" else 128, width=32)
            if wide
            else Literal(62 if concat and direction == "+:" else 63 if direction == "+:" else 64, width=32),
            Literal(select_width, width=32),
            direction,
        )

    src_selector_lhs = _selector("src[1].data")
    src_selector_rhs = _selector("src[1].data")
    dst_selector_lhs = _selector("dst.data")
    dst_selector_rhs = _selector("dst.data")
    src_lhs = Concatenation([src_selector_lhs, Identifier("src[1].valid")]) if concat else src_selector_lhs
    src_rhs = Concatenation([src_selector_rhs, Identifier("src[1].valid")]) if concat else src_selector_rhs
    dst_lhs = Concatenation([dst_selector_lhs, Identifier("dst.valid")]) if concat else dst_selector_lhs
    dst_rhs = Concatenation([dst_selector_rhs, Identifier("dst.valid")]) if concat else dst_selector_rhs
    src1 = BitSelect(Identifier("src"), Literal(1, width=32))
    rhs = Identifier("in_bit") if selector_kind == "bit" and not concat else Identifier("in_bits")
    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(src_lhs, rhs),
            ContinuousAssign(dst_lhs, src_rhs),
            ContinuousAssign(Identifier("out_bits"), dst_rhs),
        ]
    elif mode == "combo":
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([BlockingAssign(src_lhs, rhs), BlockingAssign(dst_lhs, src_rhs)]),
                sensitivity_type=SensitivityType.COMBINATIONAL,
            )
        ]
        mod.continuous_assigns = [ContinuousAssign(Identifier("out_bits"), dst_rhs)]
    else:
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([NonblockingAssign(dst_lhs, src_rhs)]),
                sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                sensitivity_type=SensitivityType.SEQUENTIAL,
            )
        ]
        mod.continuous_assigns = [
            ContinuousAssign(src_lhs, rhs),
            ContinuousAssign(Identifier("out_bits"), dst_rhs),
        ]
    mod.typedefs = [td]
    return mod


