def _make_wide_struct_signal_to_mem_field_copy(mode: str, *, concat: bool = False) -> Module:
    """Copy packed-struct signal fields into a packed-struct memory element and read them back."""
    data_width = 65
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = [
        Port("in_bus", PortDirection.INPUT, width=_w(total_width)),
        Port("out_bus", PortDirection.OUTPUT, width=_w(total_width)),
    ]
    nets = [
        Net("in_bus", NetKind.WIRE, width=_w(total_width)),
        Net("out_bus", NetKind.WIRE, width=_w(total_width)),
    ]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_signal_to_mem_field{'_concat' if concat else ''}_copy_{mode}",
        ports=ports,
        nets=nets,
        variables=[
            Variable("src", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
            Variable(
                "dst",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )
    dst0 = BitSelect(Identifier("dst"), Literal(0, width=32))
    if concat:
        dst_lhs = Concatenation([Identifier("dst[0].data"), Identifier("dst[0].valid")])
        src_rhs = Concatenation([Identifier("src.data"), Identifier("src.valid")])
        if mode == "cont":
            mod.continuous_assigns = [
                ContinuousAssign(Identifier("src"), Identifier("in_bus")),
                ContinuousAssign(dst_lhs, src_rhs),
                ContinuousAssign(Identifier("out_bus"), dst0),
            ]
        elif mode == "combo":
            mod.always_blocks = [
                AlwaysBlock(
                    SeqBlock([BlockingAssign(dst_lhs, src_rhs)]),
                    sensitivity_type=SensitivityType.COMBINATIONAL,
                )
            ]
            mod.continuous_assigns = [
                ContinuousAssign(Identifier("src"), Identifier("in_bus")),
                ContinuousAssign(Identifier("out_bus"), dst0),
            ]
        else:
            mod.always_blocks = [
                AlwaysBlock(
                    SeqBlock([NonblockingAssign(dst_lhs, src_rhs)]),
                    sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                    sensitivity_type=SensitivityType.SEQUENTIAL,
                )
            ]
            mod.continuous_assigns = [
                ContinuousAssign(Identifier("src"), Identifier("in_bus")),
                ContinuousAssign(Identifier("out_bus"), dst0),
            ]
    else:
        if mode == "cont":
            mod.continuous_assigns = [
                ContinuousAssign(Identifier("src"), Identifier("in_bus")),
                ContinuousAssign(Identifier("dst[0].data"), Identifier("src.data")),
                ContinuousAssign(Identifier("dst[0].valid"), Identifier("src.valid")),
                ContinuousAssign(Identifier("out_bus"), dst0),
            ]
        elif mode == "combo":
            mod.always_blocks = [
                AlwaysBlock(
                    SeqBlock(
                        [
                            BlockingAssign(Identifier("dst[0].data"), Identifier("src.data")),
                            BlockingAssign(Identifier("dst[0].valid"), Identifier("src.valid")),
                        ]
                    ),
                    sensitivity_type=SensitivityType.COMBINATIONAL,
                )
            ]
            mod.continuous_assigns = [
                ContinuousAssign(Identifier("src"), Identifier("in_bus")),
                ContinuousAssign(Identifier("out_bus"), dst0),
            ]
        else:
            mod.always_blocks = [
                AlwaysBlock(
                    SeqBlock(
                        [
                            NonblockingAssign(Identifier("dst[0].data"), Identifier("src.data")),
                            NonblockingAssign(Identifier("dst[0].valid"), Identifier("src.valid")),
                        ]
                    ),
                    sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                    sensitivity_type=SensitivityType.SEQUENTIAL,
                )
            ]
            mod.continuous_assigns = [
                ContinuousAssign(Identifier("src"), Identifier("in_bus")),
                ContinuousAssign(Identifier("out_bus"), dst0),
            ]
    mod.typedefs = [td]
    return mod


def _make_wide_struct_signal_to_mem_field_selector_copy(
    mode: str,
    selector_kind: str,
    *,
    dynamic: bool = False,
    direction: str = "+:",
    wide: bool = False,
    concat: bool = False,
) -> Module:
    """Copy packed-struct signal-field selectors into a packed-struct memory element and read them back."""
    data_width = 129 if wide else 65
    select_width = 65 if wide else (1 if selector_kind == "bit" else (3 if concat else 2))
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    if selector_kind == "bit" and not concat:
        ports = [
            Port("in_bus", PortDirection.INPUT, width=_w(total_width)),
            Port("out_bits", PortDirection.OUTPUT),
        ]
        nets = [
            Net("in_bus", NetKind.WIRE, width=_w(total_width)),
            Net("out_bits", NetKind.WIRE),
        ]
    else:
        io_width = select_width + 1 if concat else select_width
        ports = [
            Port("in_bus", PortDirection.INPUT, width=_w(total_width)),
            Port("out_bits", PortDirection.OUTPUT, width=_w(io_width)),
        ]
        nets = [
            Net("in_bus", NetKind.WIRE, width=_w(total_width)),
            Net("out_bits", NetKind.WIRE, width=_w(io_width)),
        ]
    if selector_kind == "range" and dynamic:
        sel_width = 8 if wide else 7
        ports.extend(
            [
                Port("msb", PortDirection.INPUT, width=_w(sel_width)),
                Port("lsb", PortDirection.INPUT, width=_w(sel_width)),
            ]
        )
        nets.extend([Net("msb", NetKind.WIRE, width=_w(sel_width)), Net("lsb", NetKind.WIRE, width=_w(sel_width))])
    if selector_kind == "part" and dynamic:
        sel_width = 8 if wide else 7
        ports.append(Port("base", PortDirection.INPUT, width=_w(sel_width)))
        nets.append(Net("base", NetKind.WIRE, width=_w(sel_width)))
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_signal_to_mem_field{'_concat' if concat else ''}{'_wide' if wide else ''}_selector_copy_{selector_kind}_{mode}_{dynamic}_{direction.replace(':', '_')}",
        ports=ports,
        nets=nets,
        variables=[
            Variable("src", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
            Variable(
                "dst",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )

    def _selector(target_name: str):
        target = Identifier(target_name)
        if selector_kind == "bit":
            return BitSelect(target, Literal(128 if wide else 64, width=32))
        if selector_kind == "range":
            return RangeSelect(
                target,
                Identifier("msb") if dynamic else Literal(128 if wide else 64, width=32),
                Identifier("lsb") if dynamic else Literal(64 if wide else 63 if not concat else 62, width=32),
            )
        return PartSelect(
            target,
            Identifier("base")
            if dynamic
            else Literal(64 if direction == "+:" else 128, width=32)
            if wide
            else Literal(62 if concat and direction == "+:" else 63 if direction == "+:" else 64, width=32),
            Literal(select_width, width=32),
            direction,
        )

    src_selector = _selector("src.data")
    dst_selector = _selector("dst[0].data")
    src_rhs = Concatenation([src_selector, Identifier("src.valid")]) if concat else src_selector
    dst_lhs = Concatenation([dst_selector, Identifier("dst[0].valid")]) if concat else dst_selector
    dst_rhs = (
        Concatenation([_selector("dst[0].data"), Identifier("dst[0].valid")]) if concat else _selector("dst[0].data")
    )
    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(Identifier("src"), Identifier("in_bus")),
            ContinuousAssign(dst_lhs, src_rhs),
            ContinuousAssign(Identifier("out_bits"), dst_rhs),
        ]
    elif mode == "combo":
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([BlockingAssign(dst_lhs, src_rhs)]),
                sensitivity_type=SensitivityType.COMBINATIONAL,
            )
        ]
        mod.continuous_assigns = [
            ContinuousAssign(Identifier("src"), Identifier("in_bus")),
            ContinuousAssign(Identifier("out_bits"), dst_rhs),
        ]
    else:
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([NonblockingAssign(dst_lhs, src_rhs)]),
                sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                sensitivity_type=SensitivityType.SEQUENTIAL,
            )
        ]
        mod.continuous_assigns = [
            ContinuousAssign(Identifier("src"), Identifier("in_bus")),
            ContinuousAssign(Identifier("out_bits"), dst_rhs),
        ]
    mod.typedefs = [td]
    return mod


def _make_wide_struct_mixed_rhs_to_signal_composed_copy(mode: str) -> Module:
    """Compose a wide packed-struct signal from mixed signal and memory pieces."""
    data_width = 129
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = [
        Port("in_mem_bus", PortDirection.INPUT, width=_w(total_width)),
        Port("in_sig_bus", PortDirection.INPUT, width=_w(total_width)),
        Port("out_bus", PortDirection.OUTPUT, width=_w(total_width)),
    ]
    nets = [
        Net("in_mem_bus", NetKind.WIRE, width=_w(total_width)),
        Net("in_sig_bus", NetKind.WIRE, width=_w(total_width)),
        Net("out_bus", NetKind.WIRE, width=_w(total_width)),
    ]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_mixed_rhs_to_signal_composed_copy_{mode}",
        ports=ports,
        nets=nets,
        variables=[
            Variable("src_sig", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
            Variable("dst_sig", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
            Variable(
                "src_mem",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )
    src1 = BitSelect(Identifier("src_mem"), Literal(1, width=32))
    rhs = Concatenation(
        [
            RangeSelect(Identifier("src_mem[1].data"), Literal(128, width=32), Literal(64, width=32)),
            RangeSelect(Identifier("src_sig.data"), Literal(63, width=32), Literal(0, width=32)),
            Identifier("src_mem[1].valid"),
        ]
    )
    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(src1, Identifier("in_mem_bus")),
            ContinuousAssign(Identifier("src_sig"), Identifier("in_sig_bus")),
            ContinuousAssign(Identifier("dst_sig"), rhs),
            ContinuousAssign(Identifier("out_bus"), Identifier("dst_sig")),
        ]
    elif mode == "combo":
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock(
                    [
                        BlockingAssign(src1, Identifier("in_mem_bus")),
                        BlockingAssign(Identifier("src_sig"), Identifier("in_sig_bus")),
                        BlockingAssign(Identifier("dst_sig"), rhs),
                    ]
                ),
                sensitivity_type=SensitivityType.COMBINATIONAL,
            )
        ]
        mod.continuous_assigns = [ContinuousAssign(Identifier("out_bus"), Identifier("dst_sig"))]
    else:
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([NonblockingAssign(Identifier("dst_sig"), rhs)]),
                sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                sensitivity_type=SensitivityType.SEQUENTIAL,
            )
        ]
        mod.continuous_assigns = [
            ContinuousAssign(src1, Identifier("in_mem_bus")),
            ContinuousAssign(Identifier("src_sig"), Identifier("in_sig_bus")),
            ContinuousAssign(Identifier("out_bus"), Identifier("dst_sig")),
        ]
    mod.typedefs = [td]
    return mod


