def _make_wide_struct_mixed_split_composed_copy(mode: str) -> Module:
    """Split a wide packed-struct signal across mixed signal and memory destinations."""
    data_width = 129
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = [
        Port("in_bus", PortDirection.INPUT, width=_w(total_width)),
        Port("out_sig_high", PortDirection.OUTPUT, width=_w(65)),
        Port("out_mem_low", PortDirection.OUTPUT, width=_w(64)),
        Port("out_valid", PortDirection.OUTPUT),
    ]
    nets = [
        Net("in_bus", NetKind.WIRE, width=_w(total_width)),
        Net("out_sig_high", NetKind.WIRE, width=_w(65)),
        Net("out_mem_low", NetKind.WIRE, width=_w(64)),
        Net("out_valid", NetKind.WIRE),
    ]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    lhs = Concatenation(
        [
            RangeSelect(Identifier("dst_sig.data"), Literal(128, width=32), Literal(64, width=32)),
            RangeSelect(Identifier("dst_mem[0].data"), Literal(63, width=32), Literal(0, width=32)),
            Identifier("dst_sig.valid"),
        ]
    )
    mod = Module(
        f"wide_struct_mixed_split_composed_copy_{mode}",
        ports=ports,
        nets=nets,
        variables=[
            Variable("src_sig", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
            Variable("dst_sig", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
            Variable(
                "dst_mem",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )
    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(Identifier("src_sig"), Identifier("in_bus")),
            ContinuousAssign(lhs, Identifier("src_sig")),
            ContinuousAssign(
                Identifier("out_sig_high"),
                RangeSelect(Identifier("dst_sig.data"), Literal(128, width=32), Literal(64, width=32)),
            ),
            ContinuousAssign(
                Identifier("out_mem_low"),
                RangeSelect(Identifier("dst_mem[0].data"), Literal(63, width=32), Literal(0, width=32)),
            ),
            ContinuousAssign(Identifier("out_valid"), Identifier("dst_sig.valid")),
        ]
    elif mode == "combo":
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock(
                    [
                        BlockingAssign(Identifier("src_sig"), Identifier("in_bus")),
                        BlockingAssign(lhs, Identifier("src_sig")),
                    ]
                ),
                sensitivity_type=SensitivityType.COMBINATIONAL,
            )
        ]
        mod.continuous_assigns = [
            ContinuousAssign(
                Identifier("out_sig_high"),
                RangeSelect(Identifier("dst_sig.data"), Literal(128, width=32), Literal(64, width=32)),
            ),
            ContinuousAssign(
                Identifier("out_mem_low"),
                RangeSelect(Identifier("dst_mem[0].data"), Literal(63, width=32), Literal(0, width=32)),
            ),
            ContinuousAssign(Identifier("out_valid"), Identifier("dst_sig.valid")),
        ]
    else:
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([NonblockingAssign(lhs, Identifier("src_sig"))]),
                sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                sensitivity_type=SensitivityType.SEQUENTIAL,
            )
        ]
        mod.continuous_assigns = [
            ContinuousAssign(Identifier("src_sig"), Identifier("in_bus")),
            ContinuousAssign(
                Identifier("out_sig_high"),
                RangeSelect(Identifier("dst_sig.data"), Literal(128, width=32), Literal(64, width=32)),
            ),
            ContinuousAssign(
                Identifier("out_mem_low"),
                RangeSelect(Identifier("dst_mem[0].data"), Literal(63, width=32), Literal(0, width=32)),
            ),
            ContinuousAssign(Identifier("out_valid"), Identifier("dst_sig.valid")),
        ]
    mod.typedefs = [td]
    return mod


