def _make_wide_struct_mem_field_selector_copy(
    mode: str, selector_kind: str, *, dynamic: bool = False, direction: str = "+:"
) -> Module:
    """Copy a narrow selector between wide packed-struct memory fields and read it back."""
    data_width = 65
    out_width = 1 if selector_kind == "bit" else 2
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = []
    nets = []
    if selector_kind == "bit":
        ports.append(Port("in_bit", PortDirection.INPUT))
        nets.append(Net("in_bit", NetKind.WIRE))
        ports.append(Port("out_bits", PortDirection.OUTPUT))
        nets.append(Net("out_bits", NetKind.WIRE))
    else:
        ports.append(Port("in_bits", PortDirection.INPUT, width=_w(out_width)))
        nets.append(Net("in_bits", NetKind.WIRE, width=_w(out_width)))
        ports.append(Port("out_bits", PortDirection.OUTPUT, width=_w(out_width)))
        nets.append(Net("out_bits", NetKind.WIRE, width=_w(out_width)))
    if selector_kind == "range" and dynamic:
        ports.extend([Port("msb", PortDirection.INPUT, width=_w(7)), Port("lsb", PortDirection.INPUT, width=_w(7))])
        nets.extend([Net("msb", NetKind.WIRE, width=_w(7)), Net("lsb", NetKind.WIRE, width=_w(7))])
    if selector_kind == "part" and dynamic:
        ports.append(Port("base", PortDirection.INPUT, width=_w(7)))
        nets.append(Net("base", NetKind.WIRE, width=_w(7)))
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_mem_field_selector_copy_{selector_kind}_{mode}_{dynamic}_{direction.replace(':', '_')}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "src",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
            Variable(
                "dst",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )

    def _selector(target_name: str):
        target = Identifier(target_name)
        if selector_kind == "bit":
            return BitSelect(target, Literal(64, width=32))
        if selector_kind == "range":
            return RangeSelect(
                target,
                Identifier("msb") if dynamic else Literal(64, width=32),
                Identifier("lsb") if dynamic else Literal(63, width=32),
            )
        return PartSelect(
            target,
            Identifier("base") if dynamic else Literal(63 if direction == "+:" else 64, width=32),
            Literal(out_width, width=32),
            direction,
        )

    src_lhs = _selector("src[1].data")
    src_rhs = _selector("src[1].data")
    dst_lhs = _selector("dst[0].data")
    dst_rhs = _selector("dst[0].data")
    rhs = Identifier("in_bit") if selector_kind == "bit" else Identifier("in_bits")
    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(src_lhs, rhs),
            ContinuousAssign(dst_lhs, src_rhs),
            ContinuousAssign(Identifier("out_bits"), dst_rhs),
        ]
    elif mode == "combo":
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock(
                    [
                        BlockingAssign(src_lhs, rhs),
                        BlockingAssign(dst_lhs, src_rhs),
                    ]
                ),
                sensitivity_type=SensitivityType.COMBINATIONAL,
            )
        ]
        mod.continuous_assigns = [ContinuousAssign(Identifier("out_bits"), dst_rhs)]
    else:
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([NonblockingAssign(dst_lhs, src_rhs)]),
                sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
                sensitivity_type=SensitivityType.SEQUENTIAL,
            )
        ]
        mod.continuous_assigns = [
            ContinuousAssign(src_lhs, rhs),
            ContinuousAssign(Identifier("out_bits"), dst_rhs),
        ]
    mod.typedefs = [td]
    return mod


def _make_wide_struct_mem_field_wide_selector_copy(
    mode: str, selector_kind: str, *, dynamic: bool = False, direction: str = "+:"
) -> Module:
    """Copy a >64-bit selector between wide packed-struct memory fields and read it back."""
    data_width = 129
