def _make_wide_struct_mem_field_wide_selector(
    mode: str,
    selector_kind: str,
    *,
    dynamic: bool = False,
    direction: str = "+:",
) -> Module:
    """Write and read back a >64-bit selector slice on a wide packed-struct memory field."""
    data_width = 129
    select_width = 65
    total_width = data_width + 1
    st = StructType(
        [
            StructField("data", "logic", width=_w(data_width)),
            StructField("valid", "logic"),
        ],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    ports = [
        Port("addr", PortDirection.INPUT, width=_w(1)),
        Port("in_bits", PortDirection.INPUT, width=_w(select_width)),
        Port("out_bits", PortDirection.OUTPUT, width=_w(select_width)),
    ]
    nets = [
        Net("addr", NetKind.WIRE, width=_w(1)),
        Net("in_bits", NetKind.WIRE, width=_w(select_width)),
        Net("out_bits", NetKind.WIRE, width=_w(select_width)),
    ]
    if selector_kind == "range" and dynamic:
        ports.extend(
            [
                Port("msb", PortDirection.INPUT, width=_w(8)),
                Port("lsb", PortDirection.INPUT, width=_w(8)),
            ]
        )
        nets.extend(
            [
                Net("msb", NetKind.WIRE, width=_w(8)),
                Net("lsb", NetKind.WIRE, width=_w(8)),
            ]
        )
    if selector_kind == "part" and dynamic:
        ports.append(Port("base", PortDirection.INPUT, width=_w(8)))
        nets.append(Net("base", NetKind.WIRE, width=_w(8)))
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))
    mod = Module(
        f"wide_struct_mem_field_wide_selector_{selector_kind}_{mode}_{dynamic}_{direction.replace(':', '_')}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "mem",
                VariableKind.REG,
                width=_w(total_width),
                type_name="wide_bus_t",
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )

    target = Identifier("mem[addr].data")
    if selector_kind == "range":
        lhs = RangeSelect(
            target,
            Identifier("msb") if dynamic else Literal(128, width=32),
            Identifier("lsb") if dynamic else Literal(64, width=32),
        )
    else:
        lhs = PartSelect(
            target,
            Identifier("base") if dynamic else Literal(64 if direction == "+:" else 128, width=32),
            Literal(select_width, width=32),
            direction,
        )

    rhs = Identifier("in_bits")
    if mode == "cont":
        mod.continuous_assigns = [ContinuousAssign(lhs, rhs), ContinuousAssign(Identifier("out_bits"), lhs)]
    else:
        assign = NonblockingAssign(lhs, rhs) if mode == "seq" else BlockingAssign(lhs, rhs)
        sensitivity_list = [SensitivityEdge("posedge", Identifier("clk"))] if mode == "seq" else None
        sensitivity_type = SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([assign]),
                sensitivity_list=sensitivity_list,
                sensitivity_type=sensitivity_type,
            )
        ]
        mod.continuous_assigns = [ContinuousAssign(Identifier("out_bits"), lhs)]
    mod.typedefs = [td]
    return mod


