def _make_wide_mem_wide_selector(
    mode: str,
    selector_kind: str,
    *,
    dynamic: bool = False,
    direction: str = "+:",
) -> Module:
    """Write and read back a >64-bit selector slice on a plain wide memory element."""
    width = 129
    select_width = 65
    ports = [
        Port("addr", PortDirection.INPUT, width=_w(1)),
        Port("in_bits", PortDirection.INPUT, width=_w(select_width)),
        Port("out_bits", PortDirection.OUTPUT, width=_w(select_width)),
    ]
    nets = [
        Net("addr", NetKind.WIRE, width=_w(1)),
        Net("in_bits", NetKind.WIRE, width=_w(select_width)),
        Net("out_bits", NetKind.WIRE, width=_w(select_width)),
    ]
    if selector_kind == "range" and dynamic:
        ports.extend(
            [
                Port("msb", PortDirection.INPUT, width=_w(8)),
                Port("lsb", PortDirection.INPUT, width=_w(8)),
            ]
        )
        nets.extend(
            [
                Net("msb", NetKind.WIRE, width=_w(8)),
                Net("lsb", NetKind.WIRE, width=_w(8)),
            ]
        )
    if selector_kind == "part" and dynamic:
        ports.append(Port("base", PortDirection.INPUT, width=_w(8)))
        nets.append(Net("base", NetKind.WIRE, width=_w(8)))
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))

    mod = Module(
        f"wide_mem_wide_selector_{selector_kind}_{mode}_{dynamic}_{direction.replace(':', '_')}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "mem",
                VariableKind.REG,
                width=_w(width),
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )
    target = BitSelect(Identifier("mem"), Identifier("addr"))
    if selector_kind == "range":
        lhs = RangeSelect(
            target,
            Identifier("msb") if dynamic else Literal(128, width=32),
            Identifier("lsb") if dynamic else Literal(64, width=32),
        )
    else:
        lhs = PartSelect(
            target,
            Identifier("base") if dynamic else Literal(64 if direction == "+:" else 128, width=32),
            Literal(select_width, width=32),
            direction,
        )

    rhs = Identifier("in_bits")
    if mode == "cont":
        mod.continuous_assigns = [ContinuousAssign(lhs, rhs), ContinuousAssign(Identifier("out_bits"), lhs)]
    else:
        assign = NonblockingAssign(lhs, rhs) if mode == "seq" else BlockingAssign(lhs, rhs)
        sensitivity_list = [SensitivityEdge("posedge", Identifier("clk"))] if mode == "seq" else None
        sensitivity_type = SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([assign]),
                sensitivity_list=sensitivity_list,
                sensitivity_type=sensitivity_type,
            )
        ]
        mod.continuous_assigns = [ContinuousAssign(Identifier("out_bits"), lhs)]
    return mod


def _make_wide_mem_concat_wide_selector(
    mode: str,
    selector_kind: str,
    *,
    dynamic: bool = False,
    direction: str = "+:",
) -> Module:
    """Write and read back a concat containing a >64-bit selector on a plain wide memory element."""
    width = 129
    select_width = 65
    total_width = select_width + 1
    ports = [
        Port("addr", PortDirection.INPUT, width=_w(1)),
        Port("in_bits", PortDirection.INPUT, width=_w(total_width)),
        Port("out_bits", PortDirection.OUTPUT, width=_w(total_width)),
    ]
    nets = [
        Net("addr", NetKind.WIRE, width=_w(1)),
        Net("in_bits", NetKind.WIRE, width=_w(total_width)),
        Net("out_bits", NetKind.WIRE, width=_w(total_width)),
    ]
    if selector_kind == "range" and dynamic:
        ports.extend(
            [
                Port("msb", PortDirection.INPUT, width=_w(8)),
                Port("lsb", PortDirection.INPUT, width=_w(8)),
            ]
        )
        nets.extend(
            [
                Net("msb", NetKind.WIRE, width=_w(8)),
                Net("lsb", NetKind.WIRE, width=_w(8)),
            ]
        )
    if selector_kind == "part" and dynamic:
        ports.append(Port("base", PortDirection.INPUT, width=_w(8)))
        nets.append(Net("base", NetKind.WIRE, width=_w(8)))
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))

    mod = Module(
        f"wide_mem_concat_wide_selector_{selector_kind}_{mode}_{dynamic}_{direction.replace(':', '_')}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "mem",
                VariableKind.REG,
                width=_w(width),
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
            Variable("flag", VariableKind.REG),
        ],
    )
    mem_elem = BitSelect(Identifier("mem"), Identifier("addr"))
    if selector_kind == "range":
        selector = RangeSelect(
            mem_elem,
            Identifier("msb") if dynamic else Literal(128, width=32),
            Identifier("lsb") if dynamic else Literal(64, width=32),
        )
    else:
        selector = PartSelect(
            mem_elem,
            Identifier("base") if dynamic else Literal(64 if direction == "+:" else 128, width=32),
            Literal(select_width, width=32),
            direction,
        )

    lhs = Concatenation([selector, Identifier("flag")])
    rhs = Identifier("in_bits")
    if mode == "cont":
        mod.continuous_assigns = [ContinuousAssign(lhs, rhs), ContinuousAssign(Identifier("out_bits"), lhs)]
    else:
        assign = NonblockingAssign(lhs, rhs) if mode == "seq" else BlockingAssign(lhs, rhs)
        sensitivity_list = [SensitivityEdge("posedge", Identifier("clk"))] if mode == "seq" else None
        sensitivity_type = SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([assign]),
                sensitivity_list=sensitivity_list,
                sensitivity_type=sensitivity_type,
            )
        ]
        mod.continuous_assigns = [ContinuousAssign(Identifier("out_bits"), lhs)]
    return mod


def _make_wide_mem_selector_read(
    mode: str, selector_kind: str, *, dynamic: bool = False, direction: str = "+:"
) -> Module:
    """Write a wide memory element from an input bus, then read back a narrow selector from it."""
    width = 65
    ports = [
        Port("addr", PortDirection.INPUT, width=_w(1)),
        Port("in_bus", PortDirection.INPUT, width=_w(width)),
    ]
    nets = [
        Net("addr", NetKind.WIRE, width=_w(1)),
        Net("in_bus", NetKind.WIRE, width=_w(width)),
    ]
    out_width = 1 if selector_kind == "bit" else 2
    if out_width == 1:
        ports.append(Port("out_bits", PortDirection.OUTPUT))
        nets.append(Net("out_bits", NetKind.WIRE))
    else:
        ports.append(Port("out_bits", PortDirection.OUTPUT, width=_w(out_width)))
        nets.append(Net("out_bits", NetKind.WIRE, width=_w(out_width)))

    if selector_kind == "range" and dynamic:
        ports.extend(
            [
                Port("msb", PortDirection.INPUT, width=_w(7)),
                Port("lsb", PortDirection.INPUT, width=_w(7)),
            ]
        )
        nets.extend(
            [
                Net("msb", NetKind.WIRE, width=_w(7)),
                Net("lsb", NetKind.WIRE, width=_w(7)),
            ]
        )
    if selector_kind == "part" and dynamic:
        ports.append(Port("base", PortDirection.INPUT, width=_w(7)))
        nets.append(Net("base", NetKind.WIRE, width=_w(7)))
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))

    mod = Module(
        f"wide_mem_selector_read_{selector_kind}_{mode}_{dynamic}_{direction.replace(':', '_')}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "mem",
                VariableKind.REG,
                width=_w(width),
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )
    mem_elem = BitSelect(Identifier("mem"), Identifier("addr"))
    if selector_kind == "bit":
        rhs_sel = BitSelect(mem_elem, Literal(64, width=32))
    elif selector_kind == "range":
        rhs_sel = RangeSelect(
            mem_elem,
            Identifier("msb") if dynamic else Literal(64, width=32),
            Identifier("lsb") if dynamic else Literal(63, width=32),
        )
    else:
        base_expr = (
            Identifier("base") if dynamic else (Literal(63, width=32) if direction == "+:" else Literal(64, width=32))
        )
        rhs_sel = PartSelect(mem_elem, base_expr, Literal(2, width=32), direction)

    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(mem_elem, Identifier("in_bus")),
            ContinuousAssign(Identifier("out_bits"), rhs_sel),
        ]
    else:
        assign = (
            NonblockingAssign(mem_elem, Identifier("in_bus"))
            if mode == "seq"
            else BlockingAssign(mem_elem, Identifier("in_bus"))
        )
        sensitivity_list = [SensitivityEdge("posedge", Identifier("clk"))] if mode == "seq" else None
        sensitivity_type = SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([assign]),
                sensitivity_list=sensitivity_list,
                sensitivity_type=sensitivity_type,
            )
        ]
        mod.continuous_assigns = [ContinuousAssign(Identifier("out_bits"), rhs_sel)]
    return mod


def _make_wide_mem_element_read(mode: str) -> Module:
    """Write a wide memory element from an input bus, then read back the whole element."""
    width = 65
    ports = [
        Port("addr", PortDirection.INPUT, width=_w(1)),
        Port("in_bus", PortDirection.INPUT, width=_w(width)),
        Port("out_bus", PortDirection.OUTPUT, width=_w(width)),
    ]
    nets = [
        Net("addr", NetKind.WIRE, width=_w(1)),
        Net("in_bus", NetKind.WIRE, width=_w(width)),
        Net("out_bus", NetKind.WIRE, width=_w(width)),
    ]
    if mode == "seq":
        ports.insert(0, Port("clk", PortDirection.INPUT))
        nets.insert(0, Net("clk", NetKind.WIRE))

    mod = Module(
        f"wide_mem_element_read_{mode}",
        ports=ports,
        nets=nets,
        variables=[
            Variable(
                "mem",
                VariableKind.REG,
                width=_w(width),
                dimensions=[Range(Literal(0, width=32), Literal(1, width=32))],
            ),
        ],
    )
    mem_elem = BitSelect(Identifier("mem"), Identifier("addr"))
    if mode == "cont":
        mod.continuous_assigns = [
            ContinuousAssign(mem_elem, Identifier("in_bus")),
            ContinuousAssign(Identifier("out_bus"), mem_elem),
        ]
    else:
        assign = (
            NonblockingAssign(mem_elem, Identifier("in_bus"))
            if mode == "seq"
            else BlockingAssign(mem_elem, Identifier("in_bus"))
        )
        sensitivity_list = [SensitivityEdge("posedge", Identifier("clk"))] if mode == "seq" else None
        sensitivity_type = SensitivityType.SEQUENTIAL if mode == "seq" else SensitivityType.COMBINATIONAL
        mod.always_blocks = [
            AlwaysBlock(
                SeqBlock([assign]),
                sensitivity_list=sensitivity_list,
                sensitivity_type=sensitivity_type,
            )
        ]
        mod.continuous_assigns = [ContinuousAssign(Identifier("out_bus"), mem_elem)]
    return mod


def _make_wide_mem_element_read_cont() -> Module:
    return _make_wide_mem_element_read("cont")


def _make_wide_mem_element_read_combo() -> Module:
    return _make_wide_mem_element_read("combo")


def _make_wide_mem_element_read_seq() -> Module:
    return _make_wide_mem_element_read("seq")


