def _make_initial_simple() -> Module:
    """Module with a simple initial block (no timing).

    initial begin
        count = 42;
    end
    """
    mod = Module(
        "init_simple",
        ports=[
            Port("count", PortDirection.OUTPUT, width=_w8()),
        ],
        nets=[],
        variables=[
            Variable("count", VariableKind.REG, width=_w8()),
        ],
    )
    mod.initial_blocks = [
        InitialBlock(
            BlockingAssign(Identifier("count"), Literal(42, width=8)),
        ),
    ]
    return mod


def _make_initial_with_delay() -> Module:
    """Module with an initial block containing timing.

    initial begin
        count = 0;
        #10 count = 5;
        #10 count = 10;
    end
    """
    mod = Module(
        "init_delay",
        ports=[
            Port("count", PortDirection.OUTPUT, width=_w8()),
        ],
        nets=[],
        variables=[
            Variable("count", VariableKind.REG, width=_w8()),
        ],
    )
    mod.initial_blocks = [
        InitialBlock(
            SeqBlock(
                [
                    BlockingAssign(Identifier("count"), Literal(0, width=8)),
                    DelayControl(Literal(10, width=32), BlockingAssign(Identifier("count"), Literal(5, width=8))),
                    DelayControl(Literal(10, width=32), BlockingAssign(Identifier("count"), Literal(10, width=8))),
                ]
            ),
        ),
    ]
    return mod


def _make_initial_with_display() -> Module:
    """Module with initial block that uses $display.

    initial begin
        x = 42;
        $display(x);
    end
    """
    mod = Module(
        "init_display",
        ports=[
            Port("x", PortDirection.OUTPUT, width=_w8()),
        ],
        nets=[],
        variables=[
            Variable("x", VariableKind.REG, width=_w8()),
        ],
    )
    mod.initial_blocks = [
        InitialBlock(
            SeqBlock(
                [
                    BlockingAssign(Identifier("x"), Literal(42, width=8)),
                    SystemTaskCall("$display", [Identifier("x")]),
                ]
            ),
        ),
    ]
    return mod


def _make_integer_modulus_initial() -> Module:
    """Initial block using a large INTEGER modulus stays defined in compiled mode."""
    mod = Module(
        "init_integer_modulus",
        ports=[
            Port("count", PortDirection.OUTPUT, width=Range(Literal(31, width=32), Literal(0, width=32))),
        ],
        nets=[],
        variables=[
            Variable("count", VariableKind.REG, width=Range(Literal(31, width=32), Literal(0, width=32))),
            Variable("modulus", VariableKind.INTEGER),
        ],
    )
    mod.initial_blocks = [
        InitialBlock(
            SeqBlock(
                [
                    BlockingAssign(
                        Identifier("modulus"),
                        BinaryOp("**", Literal(2, width=32), Literal(32, width=32)),
                    ),
                    BlockingAssign(
                        Identifier("count"),
                        BinaryOp("%", Literal(7, width=32), Identifier("modulus")),
                    ),
                ]
            )
        ),
    ]
    return mod


def _make_always_timing_clock() -> Module:
    """Module with always block that generates a clock via timing.

    always #5 clk = ~clk;
    assign out = clk;
    """
    mod = Module(
        "always_clk",
        ports=[
            Port("clk", PortDirection.OUTPUT),
            Port("out", PortDirection.OUTPUT),
        ],
        nets=[
            Net("out", NetKind.WIRE),
        ],
        variables=[
            Variable("clk", VariableKind.REG),
        ],
        continuous_assigns=[
            ContinuousAssign(Identifier("out"), Identifier("clk")),
        ],
    )
    mod.always_blocks = [
        AlwaysBlock(
            DelayControl(
                Literal(5, width=32),
                BlockingAssign(Identifier("clk"), UnaryOp("~", Identifier("clk"))),
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        ),
    ]
    return mod


