class TestPhase4Execution:
    """Test initial block fallback and timing support."""

    def test_initial_simple(self):
        """Simple initial block sets signal to 42."""
        sim = Simulator(_make_initial_simple(), engine="compiled")
        sim.run(max_time=0)
        assert sim.read("count") == Value(42, width=8)

    def test_initial_with_delay(self):
        """Initial block with #delay sets values at correct times."""
        sim = Simulator(_make_initial_with_delay(), engine="compiled")

        # After t=0: count=0
        # After t=10: count=5
        # After t=20: count=10
        sim.run(max_time=25)
        assert sim.read("count") == Value(10, width=8)

    def test_initial_with_display(self):
        """Initial block $display output is captured."""
        sim = Simulator(_make_initial_with_display(), engine="compiled")
        sim.run(max_time=0)
        assert sim.read("x") == Value(42, width=8)
        # $display output should have been captured
        assert len(sim.display_output) >= 1
        assert "42" in sim.display_output[0]

    def test_always_timing_clock(self):
        """Always #5 clk = ~clk toggling works via fallback."""
        sim = Simulator(_make_always_timing_clock(), engine="compiled")
        sim.run(max_time=25)
        # After several toggles, out should reflect clk
        # At t=0: clk=x (initial), t=5: clk=~x, ...
        # The exact value depends on x semantics; just check no crash

    def test_initial_counter_setup(self):
        """Initial block sets up reset, then counter counts on clock."""
        mod = _make_initial_counter_setup()
        sim = Simulator(mod, engine="compiled")
        clk = Clock(sim.signal("clk"), period=10)
        sim.fork(clk)
        sim.run(max_time=100)
        # After reset released at t=20, counter should have counted
        count = sim.read("count")
        assert count.is_defined
        assert int(count) > 0

    def test_initial_finish(self):
        """$finish in initial block stops simulation."""
        sim = Simulator(_make_initial_finish(), engine="compiled")
        sim.run(max_time=100)
        # x should be 99 (set before $finish)
        assert sim.read("x") == Value(99, width=8)

    def test_integer_modulus_initial(self):
        """Large INTEGER assignments do not get truncated to zero in compiled mode."""
        sim = Simulator(_make_integer_modulus_initial(), engine="compiled")
        sim.run(max_time=0)
        assert sim.read("count") == Value(7, width=32)


# ── Phase 4: VCD recording ──────────────────────────────────────────


class TestPhase4VCD:
    """Test VCD recording with compiled engine."""

    def test_vcd_time_step_callback(self):
        """_on_time_step callback fires for each time step."""
        sim = Simulator(_make_counter(), engine="compiled")
        sim.drive("rst", Value(1, width=1))
        sim.drive("count", Value(0, width=8))
        clk = Clock(sim.signal("clk"), period=10)
        sim.fork(clk)

        times_seen = []

        def record(sched):
            times_seen.append(sched.time)

        sim._sched._on_time_step = record
        sim.run(max_time=50)

        # Should have callbacks at t=0 and each clock edge
        assert len(times_seen) > 0
        assert times_seen[0] == 0

    def test_vcd_ctx_signals_access(self):
        """sched.ctx._signals provides dict-like access for VCD."""
        sim = Simulator(_make_adder(), engine="compiled")
        sim.drive("a", Value(3, width=8))
        sim.drive("b", Value(5, width=8))
        sim.run(max_time=0)

        sched = sim._sched
        # Access via ctx._signals (dict-like interface)
        signals = sched.ctx._signals
        assert "a" in signals
        assert "b" in signals
        assert "y" in signals
        assert signals["y"] == Value(8, width=8)

        # items() should work for VCD recording loop
        sig_dict = dict(signals.items())
        assert sig_dict["a"] == Value(3, width=8)
        assert sig_dict["b"] == Value(5, width=8)

    def test_vcd_recording(self):
        """Full VCD recording works with compiled engine."""
        import io  # noqa: PLC0415

        from veriforge.sim.vcd import VcdWriter  # noqa: PLC0415

        sim = Simulator(_make_counter(), engine="compiled")
        sim.drive("rst", Value(1, width=1))
        sim.drive("count", Value(0, width=8))
        clk = Clock(sim.signal("clk"), period=10)
        sim.fork(clk)

        vcd_buf = io.StringIO()
        vcd_writer = VcdWriter(vcd_buf, timescale="1ns")

        for name in ["clk", "rst", "count"]:
            sig_val = sim._sched.ctx._signals[name]
            vcd_writer.add_signal(name, width=sig_val.width)

        vcd_writer.write_header()
        initial_vals = dict(sim._sched.ctx._signals.items())
        vcd_writer.write_initial(initial_vals)

        def _record_signals(sched):
            vcd_writer.set_time(sched.time)
            for name in sched.ctx._signals:
                vcd_writer.change(name, sched.ctx._signals[name])

        sim._sched._on_time_step = _record_signals
        sim.run(max_time=50)
        vcd_writer.finalize()

        vcd_text = vcd_buf.getvalue()
        assert "$timescale" in vcd_text
        assert "$var" in vcd_text
        assert "$dumpvars" in vcd_text


# ── Phase 4: Cross-validation ───────────────────────────────────────


class TestPhase4CrossValidation:
    """Cross-validate Phase 4 features across engines."""

    ENGINES = ["vm", "vm-fast", "compiled"]  # noqa: RUF012

    def _run_clocked(self, module_fn, setup_fn, signals_to_check, max_steps=20, clock_period=10):
        """Run module through all engines with clock, compare after each step."""
        max_time = max_steps * clock_period + clock_period
        results = {}
        for eng in self.ENGINES:
            mod = module_fn()
            sim = Simulator(mod, engine=eng)
            setup_fn(sim)
            clk = Clock(sim.signal("clk"), period=clock_period)
            sim.fork(clk)
            sim._schedule_clock_events(clk, max_time)
            values = []
            for _ in range(max_steps):
                if not sim.run_step():
                    break
                values.append({name: sim.read(name) for name in signals_to_check})
            results[eng] = values

        ref_vals = results["vm"]
        for eng in ["compiled"]:
            eng_vals = results[eng]
            assert len(eng_vals) == len(ref_vals), f"{eng}: got {len(eng_vals)} steps, expected {len(ref_vals)}"
            for step_i, (ref_step, eng_step) in enumerate(zip(ref_vals, eng_vals, strict=True)):
                for sig in signals_to_check:
                    assert eng_step[sig] == ref_step[sig], (
                        f"{eng} step {step_i} disagrees on '{sig}': {eng_step[sig]} != {ref_step[sig]}"
                    )

    def test_initial_simple_cross(self):
        """Simple initial block cross-validated."""
        results = {}
        for eng in self.ENGINES:
            sim = Simulator(_make_initial_simple(), engine=eng)
            sim.run(max_time=0)
            results[eng] = sim.read("count")

        assert results["compiled"] == results["vm"]

    def test_initial_delay_cross(self):
        """Initial block with #delay cross-validated."""
        results = {}
        for eng in self.ENGINES:
            sim = Simulator(_make_initial_with_delay(), engine=eng)
            sim.run(max_time=25)
            results[eng] = sim.read("count")

        assert results["compiled"] == results["vm"]

    def test_initial_display_cross(self):
        """$display in initial block cross-validated."""
        results = {}
        for eng in self.ENGINES:
            sim = Simulator(_make_initial_with_display(), engine=eng)
            sim.run(max_time=0)
            results[eng] = {
                "x": sim.read("x"),
                "display_count": len(sim.display_output),
            }

        assert results["compiled"]["x"] == results["vm"]["x"]
        assert results["compiled"]["display_count"] == results["vm"]["display_count"]


# ── Bug regression: parameter resolution ────────────────────────────


def _make_fsm_with_params():
    """Module using parameters in case statement (FSM state encoding).

    module fsm(input clk, output reg [1:0] state);
      parameter IDLE = 0, RUNNING = 1, DONE = 2;
      always @(posedge clk) begin
        case (state)
          IDLE:    state <= RUNNING;
          RUNNING: state <= DONE;
          DONE:    state <= IDLE;
          default: state <= IDLE;
        endcase
      end
    endmodule
    """
    from veriforge.model.parameters import Parameter

    w2 = Range(Literal(1, width=32), Literal(0, width=32))
    m = Module(
        "fsm",
        ports=[
            Port("clk", PortDirection.INPUT),
            Port("state", PortDirection.OUTPUT, width=w2),
        ],
    )
    m.nets = [Net("clk", NetKind.WIRE)]
    m.variables = [Variable("state", VariableKind.REG, width=w2)]
    m.parameters = [
        Parameter("IDLE", default_value=Literal(0, width=32)),
        Parameter("RUNNING", default_value=Literal(1, width=32)),
        Parameter("DONE", default_value=Literal(2, width=32)),
    ]
    # always @(posedge clk) case (state) ...
    m.always_blocks = [
        AlwaysBlock(
            sensitivity_type=SensitivityType.SEQUENTIAL,
            sensitivity_list=[SensitivityEdge(Identifier("clk"), "posedge")],
            body=CaseStatement(
                "case",
                Identifier("state"),
                [
                    CaseItem([Identifier("IDLE")], NonblockingAssign(Identifier("state"), Literal(1, width=2))),
                    CaseItem([Identifier("RUNNING")], NonblockingAssign(Identifier("state"), Literal(2, width=2))),
                    CaseItem([Identifier("DONE")], NonblockingAssign(Identifier("state"), Literal(0, width=2))),
                    CaseItem(None, NonblockingAssign(Identifier("state"), Literal(0, width=2)), is_default=True),
                ],
            ),
        )
    ]
    return m


class TestParameterResolutionRegression:
    """Bug regression: parameters were resolving to 0 in compiled engine."""

    ENGINES = ["reference", "vm", "vm-fast", "compiled"]  # noqa: RUF012

    def test_fsm_parameter_states_cross(self):
        """FSM with parameter-encoded states should cycle correctly across all engines."""
        for eng in self.ENGINES:
            sim = Simulator(_make_fsm_with_params(), engine=eng)
            clk = Clock(sim.signal("clk"), period=10)
            sim.fork(clk)
            sim.drive("state", Value(0, width=2))  # start at IDLE

            # Run 3 full clock cycles (period=10 each, so 30 time units)
            sim.run(max_time=30)
            state_final = int(sim.read("state"))

            # After 3 cycles: IDLE→RUNNING→DONE→IDLE, should be back to 0
            assert state_final == 0, f"{eng}: expected IDLE=0 after 3 cycles, got {state_final}"


# ── Bug regression: memory array dimension detection ────────────────


class TestMemoryArrayDimensionRegression:
    """Bug regression: reg [7:0] regfile [0:7] had dimensions=[]."""

    def test_reg_memory_dimensions_from_parser(self):
        """Parsed reg with array dimensions should have non-empty dimensions list."""
        from veriforge.transforms.tree_to_model import tree_to_design
        from veriforge.verilog_parser import verilog_parser

        parser = verilog_parser(start="source_text")
        tree = parser.build_tree(text="module t; reg [7:0] regfile [0:7]; endmodule")
        design = tree_to_design(tree)
        v = design.modules[0].variables[0]
        assert v.name == "regfile"
        assert len(v.dimensions) == 1
        assert int(v.dimensions[0].msb.value) == 0
        assert int(v.dimensions[0].lsb.value) == 7

    def test_net_memory_dimensions_from_parser(self):
        """Parsed wire with array dimensions should have non-empty dimensions list."""
        from veriforge.transforms.tree_to_model import tree_to_design
        from veriforge.verilog_parser import verilog_parser

        parser = verilog_parser(start="source_text")
        tree = parser.build_tree(text="module t; wire [3:0] mem_net [0:15]; endmodule")
        design = tree_to_design(tree)
        n = design.modules[0].nets[0]
        assert n.name == "mem_net"
        assert len(n.dimensions) == 1
        assert int(n.dimensions[0].msb.value) == 0
        assert int(n.dimensions[0].lsb.value) == 15


