# ── Bug regression: unconditional dirty marking ─────────────────────


def _make_stable_combo():
    """Module with combinational logic that stabilises in 1 delta.

    module stable(input a, output y, output z);
      assign y = a;
      assign z = a & 1'b1;
    endmodule

    Both outputs mirror `a`.  With unconditional dirty marking the compiled
    engine could waste delta iterations; with the fix only the first delta
    marks them dirty.
    """
    return Module(
        "stable",
        ports=[
            Port("a", PortDirection.INPUT),
            Port("y", PortDirection.OUTPUT),
            Port("z", PortDirection.OUTPUT),
        ],
        nets=[
            Net("y", NetKind.WIRE),
            Net("z", NetKind.WIRE),
        ],
        variables=[],
        continuous_assigns=[
            ContinuousAssign(Identifier("y"), Identifier("a")),
            ContinuousAssign(Identifier("z"), BinaryOp("&", Identifier("a"), Literal(1, width=1))),
        ],
    )


class TestDirtyMarkingRegression:
    """Bug regression: compiled engine unconditionally marked signals dirty."""

    ENGINES = ["reference", "vm", "vm-fast", "compiled"]  # noqa: RUF012

    def test_stable_combo_cross(self):
        """Stable combinational logic should produce identical results across engines."""
        for eng in self.ENGINES:
            sim = Simulator(_make_stable_combo(), engine=eng)
            sim.drive("a", Value(1, width=1))
            sim.run(max_time=0)

            assert int(sim.read("y")) == 1, f"{eng}: y should be 1"
            assert int(sim.read("z")) == 1, f"{eng}: z should be 1"

            # Change input
            sim.drive("a", Value(0, width=1))
            sim.run(max_time=10)

            assert int(sim.read("y")) == 0, f"{eng}: y should be 0 after a=0"
            assert int(sim.read("z")) == 0, f"{eng}: z should be 0 after a=0"


