def _make_multidim_memory_probe() -> Module:
    """Module exercising compiled multi-dimensional unpacked memory accesses."""
    row0 = Literal(0, width=32)
    row1 = Literal(1, width=32)
    col0 = Literal(0, width=32)
    col1 = Literal(1, width=32)
    col2 = Literal(2, width=32)
    mem_12 = BitSelect(BitSelect(Identifier("mem"), row1), col2)
    mem_01 = BitSelect(BitSelect(Identifier("mem"), row0), col1)
    mem_00 = BitSelect(BitSelect(Identifier("mem"), row0), col0)

    mod = Module(
        "multidim_memory_probe",
        ports=[
            Port("row", PortDirection.INPUT),
            Port("col", PortDirection.INPUT, width=_w(2)),
            Port("y", PortDirection.OUTPUT, width=_w8()),
            Port("lane", PortDirection.OUTPUT, width=_w8()),
            Port("copied", PortDirection.OUTPUT, width=_w8()),
        ],
        nets=[],
        variables=[
            Variable("y", VariableKind.REG, width=_w8()),
            Variable("lane", VariableKind.REG, width=_w8()),
            Variable("copied", VariableKind.REG, width=_w8()),
            Variable(
                "mem",
                VariableKind.REG,
                width=_w8(),
                dimensions=[
                    Range(Literal(0, width=32), Literal(1, width=32)),
                    Range(Literal(0, width=32), Literal(2, width=32)),
                ],
            ),
        ],
    )
    mod.initial_blocks = [
        InitialBlock(
            SeqBlock(
                [
                    BlockingAssign(mem_12, Literal(0xA5, width=8)),
                    BlockingAssign(mem_01, Literal(0x3C, width=8)),
                    BlockingAssign(
                        RangeSelect(mem_01, Literal(7, width=32), Literal(4, width=32)), Literal(0xD, width=4)
                    ),
                    BlockingAssign(mem_00, mem_12),
                    BlockingAssign(Identifier("lane"), mem_01),
                    BlockingAssign(Identifier("copied"), mem_00),
                ]
            )
        )
    ]
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(
                Identifier("y"), BitSelect(BitSelect(Identifier("mem"), Identifier("row")), Identifier("col"))
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        )
    ]
    return mod


def _make_inout_port_probe() -> Module:
    """Module with a raw inout port driven by local combinational logic."""
    return Module(
        "inout_port_probe",
        ports=[
            Port("bus", PortDirection.INOUT, width=_w8()),
            Port("drive_val", PortDirection.INPUT, width=_w8()),
            Port("drive_en", PortDirection.INPUT),
            Port("out", PortDirection.OUTPUT, width=_w8()),
        ],
        nets=[
            Net("bus", NetKind.WIRE, width=_w8()),
            Net("drive_val", NetKind.WIRE, width=_w8()),
            Net("drive_en", NetKind.WIRE),
            Net("out", NetKind.WIRE, width=_w8()),
        ],
        continuous_assigns=[
            ContinuousAssign(
                Identifier("bus"),
                TernaryOp(
                    Identifier("drive_en"),
                    Identifier("drive_val"),
                    Literal(0, width=8),
                ),
            ),
            ContinuousAssign(Identifier("out"), Identifier("bus")),
        ],
    )


def _make_native_initial() -> Module:
    """Module with simple initial block (no timing, no system tasks).

    initial begin
        count = 42;
        flag = 1;
    end
    """
    mod = Module(
        "native_init",
        ports=[
            Port("count", PortDirection.OUTPUT, width=_w8()),
            Port("flag", PortDirection.OUTPUT),
        ],
        nets=[],
        variables=[
            Variable("count", VariableKind.REG, width=_w8()),
            Variable("flag", VariableKind.REG),
        ],
    )
    mod.initial_blocks = [
        InitialBlock(
            SeqBlock(
                [
                    BlockingAssign(Identifier("count"), Literal(42, width=8)),
                    BlockingAssign(Identifier("flag"), Literal(1, width=1)),
                ]
            ),
        ),
    ]
    return mod


class TestPhase7Codegen:
    """Verify Phase 7 codegen features and guards."""

    def test_signed_codegen(self):
        """$signed emits _sign_ext helper call."""
        cg = CythonCodegen()
        pyx = cg.generate(_make_signed_arith())
        assert "_sign_ext" in pyx

    def test_power_codegen(self):
        """Power operator uses libc pow."""
        cg = CythonCodegen()
        pyx = cg.generate(_make_power())
        assert "pow" in pyx
        assert "from libc.math cimport pow" in pyx

    def test_xnor_reduce_codegen(self):
        """XNOR reduction uses _xor_reduce with correct logic."""
        cg = CythonCodegen()
        pyx = cg.generate(_make_xnor_reduce())
        assert "_xor_reduce" in pyx
        assert "else 0" in pyx

    def test_native_initial_codegen(self):
        """Simple initial block compiles into __init__ (not fallback)."""
        cg = CythonCodegen()
        pyx = cg.generate(_make_native_initial())
        # The initial assignments should appear in the __init__ method
        assert "42" in pyx
        # No timing fallback needed
        assert not cg.has_timing_initials

    def test_initial_with_display_needs_fallback(self):
        """Initial block with $display falls back to reference executor."""
        cg = CythonCodegen()
        cg.generate(_make_initial_with_display())
        assert cg.has_timing_initials

    def test_inout_codegen(self):
        """Raw inout ports compile like ordinary top-level wires."""
        mod = _make_inout_port_probe()
        cg = CythonCodegen()
        code = cg.generate(mod)
        assert "c.val" in code
        assert "bus" in cg.signal_map

    def test_instance_raises(self):
        """Module instantiation raises NotImplementedError."""
        mod = Module(
            "inst_test",
            ports=[],
            nets=[],
            variables=[],
        )
        mod.instances = [Instance("child_mod", "u0")]
        cg = CythonCodegen()
        with pytest.raises(NotImplementedError, match="instantiation"):
            cg.generate(mod)

    def test_while_generates_loop(self):
        """While loop emits guarded loop code instead of raising."""
        mod = _make_while_counter()
        cg = CythonCodegen()
        code = cg.generate(mod)
        assert "while True:" in code
        assert "ERR_WHILE_LOOP_LIMIT" in code

    def test_repeat_generates_loop(self):
        """Repeat loop in always block emits a finite loop instead of raising."""
        mod = _make_repeat_counter()
        cg = CythonCodegen()
        code = cg.generate(mod)
        assert "for _lv_repeat_i_0 in range(_lv_repeat_count_0):" in code

    def test_forever_generates_loop(self):
        """Forever loop emits guarded loop code instead of raising."""
        mod = _make_forever_finish_counter()
        cg = CythonCodegen()
        code = cg.generate(mod)
        assert "ERR_FOREVER_LOOP_LIMIT" in code
        assert "while True:" in code

    def test_multidim_memory_codegen(self):
        """Multi-dimensional unpacked arrays flatten into compiled memory storage."""
        mod = _make_multidim_memory_probe()
        cg = CythonCodegen()
        code = cg.generate(mod)
        mid = cg.mem_map["mem"]
        assert cg.mem_info[mid] == (8, 6)
        assert f"c.mem_{mid}_val" in code

    def test_task_enable_unknown_emits_pass(self):
        """Unknown task enable emits harmless pass comment instead of raising."""
        mod = Module(
            "task_test",
            ports=[Port("out", PortDirection.OUTPUT, width=_w8())],
            nets=[],
            variables=[Variable("out", VariableKind.REG, width=_w8())],
        )
        mod.always_blocks = [
            AlwaysBlock(
                TaskEnable("my_task", [Identifier("out")]),
                sensitivity_type=SensitivityType.COMBINATIONAL,
            ),
        ]
        cg = CythonCodegen()
        code = cg.generate(mod)
        assert "unknown task: my_task" in code

    def test_casex_generates_code(self):
        """casex generates mask-aware comparison code."""
        mod = Module(
            "casex_test",
            ports=[
                Port("sel", PortDirection.INPUT, width=_w8()),
                Port("out", PortDirection.OUTPUT, width=_w8()),
            ],
            nets=[],
            variables=[
                Variable("sel", VariableKind.REG, width=_w8()),
                Variable("out", VariableKind.REG, width=_w8()),
            ],
        )
        mod.always_blocks = [
            AlwaysBlock(
                CaseStatement(
                    "casex",
                    Identifier("sel"),
                    [CaseItem([Literal(0, width=8)], BlockingAssign(Identifier("out"), Literal(0, width=8)))],
                ),
                sensitivity_type=SensitivityType.COMBINATIONAL,
            ),
        ]
        cg = CythonCodegen()
        code = cg.generate(mod)
        assert "casex" not in code or "sel_mask" in code or "item_mask" in code


class TestPhase7Runtime:
    """Verify Phase 7 features at runtime (compile + execute)."""

    @pytest.fixture()
    def compiler(self, tmp_path):
        return CythonCompiler(cache_dir=str(tmp_path / "cache"))

    def test_signed_right_shift(self, compiler):
        """$signed(a) >>> 2 sign-extends before shifting."""
        mod = _make_signed_arith()
        cg = CythonCodegen()
        pyx = cg.generate(mod)
        compiled_mod = compiler.compile_pyx(pyx, "compiled_signed_arith")
        sim = compiled_mod.CompiledSim()
        sid_a, sid_y = cg.signal_map["a"], cg.signal_map["y"]
        sim.drive(sid_a, 0xF0, 0)  # a = 0xF0 (negative in signed 8-bit)
        sim.step()
        v, _m = sim.read(sid_y)
        # $signed(0xF0) >>> 2 = -16 >>> 2 = -4 = 0xFC in 8-bit unsigned
        assert (v & 0xFF) == 0xFC

    def test_signed_positive_shift(self, compiler):
        """Signed right shift of positive value."""
        mod = _make_signed_arith()
        cg = CythonCodegen()
        pyx = cg.generate(mod)
        compiled_mod = compiler.compile_pyx(pyx, "compiled_signed_pos")
        sim = compiled_mod.CompiledSim()
        sid_a, sid_y = cg.signal_map["a"], cg.signal_map["y"]
        sim.drive(sid_a, 0x40, 0)  # a = 0x40 = 64
        sim.step()
        v, _m = sim.read(sid_y)
        # $signed(0x40) >>> 2 = 64 >>> 2 = 16 = 0x10
        assert (v & 0xFF) == 0x10

    def test_power_op(self, compiler):
        """a ** b computes power."""
        mod = _make_power()
        cg = CythonCodegen()
        pyx = cg.generate(mod)
        compiled_mod = compiler.compile_pyx(pyx, "compiled_power")
        sim = compiled_mod.CompiledSim()
        sid_a, sid_b, sid_y = cg.signal_map["a"], cg.signal_map["b"], cg.signal_map["y"]
        sim.drive(sid_a, 2, 0)  # a = 2
        sim.drive(sid_b, 8, 0)  # b = 8
        sim.step()
        v, _m = sim.read(sid_y)
        assert (v & 0xFFFF) == 256  # 2**8 = 256

    def test_power_zero_exponent(self, compiler):
        """a ** 0 = 1."""
        mod = _make_power()
        cg = CythonCodegen()
        pyx = cg.generate(mod)
        compiled_mod = compiler.compile_pyx(pyx, "compiled_power_zero")
        sim = compiled_mod.CompiledSim()
        sid_a, sid_b, sid_y = cg.signal_map["a"], cg.signal_map["b"], cg.signal_map["y"]
        sim.drive(sid_a, 10, 0)  # a = 10
        sim.drive(sid_b, 0, 0)  # b = 0
        sim.step()
        v, _m = sim.read(sid_y)
        assert (v & 0xFFFF) == 1  # 10**0 = 1

    def test_xnor_reduction(self, compiler):
        """XNOR reduction: ~^0xFF = 1 (even parity), ~^0x01 = 0 (odd parity)."""
        mod = _make_xnor_reduce()
        cg = CythonCodegen()
        pyx = cg.generate(mod)
        compiled_mod = compiler.compile_pyx(pyx, "compiled_xnor_red")
        sim = compiled_mod.CompiledSim()
        sid_a, sid_y = cg.signal_map["a"], cg.signal_map["y"]

        # 0xFF has 8 ones → even parity → ~^0xFF = 1
        sim.drive(sid_a, 0xFF, 0)
        sim.step()
        v, _m = sim.read(sid_y)
        assert (v & 1) == 1

        # 0x01 has 1 one → odd parity → ~^0x01 = 0
        sim.drive(sid_a, 0x01, 0)
        sim.step()
        v, _m = sim.read(sid_y)
        assert (v & 1) == 0

    def test_repeat_loop(self, compiler):
        """Combinational repeat loop compiles and executes in the compiled engine."""
        mod = _make_repeat_counter()
        cg = CythonCodegen()
        pyx = cg.generate(mod)
        compiled_mod = compiler.compile_pyx(pyx, "compiled_repeat_counter")
        sim = compiled_mod.CompiledSim()
        sid_count, sid_y = cg.signal_map["count"], cg.signal_map["y"]

        sim.drive(sid_count, 3, 0)
        sim.step()
        v, _m = sim.read(sid_y)
        assert (v & 0xFF) == 3

        sim.drive(sid_count, 0, 0)
        sim.step()
        v, _m = sim.read(sid_y)
        assert (v & 0xFF) == 0

    def test_while_loop(self, compiler):
        """Combinational while loop compiles and executes in the compiled engine."""
        mod = _make_while_counter()
        cg = CythonCodegen()
        pyx = cg.generate(mod)
        compiled_mod = compiler.compile_pyx(pyx, "compiled_while_counter")
        sim = compiled_mod.CompiledSim()
        sid_count, sid_y = cg.signal_map["count"], cg.signal_map["y"]

        sim.drive(sid_count, 4, 0)
        sim.step()
        v, _m = sim.read(sid_y)
        assert (v & 0xFF) == 4

        sim.drive(sid_count, 1, 0)
        sim.step()
        v, _m = sim.read(sid_y)
        assert (v & 0xFF) == 1

    def test_while_loop_limit_raises(self, compiler):
        """Infinite compiled while loop raises the shared loop-limit error."""
        mod = _make_infinite_while()
