def _make_wide_struct_field_binop(op: str = "|") -> Module:
    """assign y = bus_a.data <op> bus_b.data — wide struct signal field reads in compound expr."""
    data_width = 65
    total_width = data_width + 1  # valid(1) at bit 0, data(65) at bits [65:1]
    op_tag = {"&": "and", "|": "or", "^": "xor"}[op]
    st = StructType(
        [StructField("data", "logic", width=_w(data_width)), StructField("valid", "logic")],
        packed=True,
    )
    td = TypedefDecl("wide_bus_t", struct_type=st)
    mod = Module(
        f"wide_struct_field_binop_{op_tag}",
        ports=[
            Port("in_a", PortDirection.INPUT, width=_w(total_width)),
            Port("in_b", PortDirection.INPUT, width=_w(total_width)),
            Port("y", PortDirection.OUTPUT, width=_w(data_width)),
        ],
        nets=[
            Net("in_a", NetKind.WIRE, width=_w(total_width)),
            Net("in_b", NetKind.WIRE, width=_w(total_width)),
            Net("y", NetKind.WIRE, width=_w(data_width)),
        ],
        variables=[
            Variable("bus_a", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
            Variable("bus_b", VariableKind.REG, width=_w(total_width), type_name="wide_bus_t"),
        ],
        continuous_assigns=[
            ContinuousAssign(Identifier("bus_a"), Identifier("in_a")),
            ContinuousAssign(Identifier("bus_b"), Identifier("in_b")),
            ContinuousAssign(
                Identifier("y"),
                BinaryOp(op, Identifier("bus_a.data"), Identifier("bus_b.data")),
            ),
        ],
    )
    mod.typedefs = [td]
    return mod


