def _make_wide_cont_multi_bitwise(width: int) -> Module:
    """assign y_and=a&b; assign y_or=a|b; assign y_xor=a^b — all three bitwise ops in one DUT.

    Harness-DUT consolidation: three parametrize rows share one compiled module instead of three.
    """
    return Module(
        f"wide_cont_multi_bw_{width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("b", PortDirection.INPUT, width=_w(width)),
            Port("y_and", PortDirection.OUTPUT, width=_w(width)),
            Port("y_or", PortDirection.OUTPUT, width=_w(width)),
            Port("y_xor", PortDirection.OUTPUT, width=_w(width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("b", NetKind.WIRE, width=_w(width)),
            Net("y_and", NetKind.WIRE, width=_w(width)),
            Net("y_or", NetKind.WIRE, width=_w(width)),
            Net("y_xor", NetKind.WIRE, width=_w(width)),
        ],
        continuous_assigns=[
            ContinuousAssign(Identifier("y_and"), BinaryOp("&", Identifier("a"), Identifier("b"))),
            ContinuousAssign(Identifier("y_or"), BinaryOp("|", Identifier("a"), Identifier("b"))),
            ContinuousAssign(Identifier("y_xor"), BinaryOp("^", Identifier("a"), Identifier("b"))),
        ],
    )


def _make_wide_combo_multi_bitwise(width: int) -> Module:
    """always @(*) begin y_and=a&b; y_or=a|b; y_xor=a^b; end — blocking-assign multi-op DUT."""
    mod = Module(
        f"wide_combo_multi_bw_{width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("b", PortDirection.INPUT, width=_w(width)),
            Port("y_and", PortDirection.OUTPUT, width=_w(width)),
            Port("y_or", PortDirection.OUTPUT, width=_w(width)),
            Port("y_xor", PortDirection.OUTPUT, width=_w(width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("b", NetKind.WIRE, width=_w(width)),
        ],
        variables=[
            Variable("y_and", VariableKind.REG, width=_w(width)),
            Variable("y_or", VariableKind.REG, width=_w(width)),
            Variable("y_xor", VariableKind.REG, width=_w(width)),
        ],
    )
    mod.always_blocks = [
        AlwaysBlock(
            SeqBlock(
                [
                    BlockingAssign(Identifier("y_and"), BinaryOp("&", Identifier("a"), Identifier("b"))),
                    BlockingAssign(Identifier("y_or"), BinaryOp("|", Identifier("a"), Identifier("b"))),
                    BlockingAssign(Identifier("y_xor"), BinaryOp("^", Identifier("a"), Identifier("b"))),
                ]
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        ),
    ]
    return mod


def _make_wide_seq_multi_bitwise(width: int) -> Module:
    """always @(posedge clk) begin q_and<=a&b; q_or<=a|b; q_xor<=a^b; end — NBA multi-op DUT."""
    mod = Module(
        f"wide_seq_multi_bw_{width}",
        ports=[
            Port("clk", PortDirection.INPUT),
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("b", PortDirection.INPUT, width=_w(width)),
            Port("q_and", PortDirection.OUTPUT, width=_w(width)),
            Port("q_or", PortDirection.OUTPUT, width=_w(width)),
            Port("q_xor", PortDirection.OUTPUT, width=_w(width)),
        ],
        nets=[
            Net("clk", NetKind.WIRE),
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("b", NetKind.WIRE, width=_w(width)),
        ],
        variables=[
            Variable("q_and", VariableKind.REG, width=_w(width)),
            Variable("q_or", VariableKind.REG, width=_w(width)),
            Variable("q_xor", VariableKind.REG, width=_w(width)),
        ],
    )
    mod.always_blocks = [
        AlwaysBlock(
            SeqBlock(
                [
                    NonblockingAssign(Identifier("q_and"), BinaryOp("&", Identifier("a"), Identifier("b"))),
                    NonblockingAssign(Identifier("q_or"), BinaryOp("|", Identifier("a"), Identifier("b"))),
                    NonblockingAssign(Identifier("q_xor"), BinaryOp("^", Identifier("a"), Identifier("b"))),
                ]
            ),
            sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
            sensitivity_type=SensitivityType.SEQUENTIAL,
        ),
    ]
    return mod


