class TestWideUnifiedBehavioralCrossVal:
    """Phase 1 behavioral cross-validation: compiled vs vm for wide operators.

    Each test compiles a module and runs it with both engines, verifying
    the recursive wide emitter produces correct simulation output.
    """

    _W65 = (1 << 64) | 0x1234_5678_9ABC_DEF0
    _W65b = (1 << 63) | 0x0FED_CBA9_8765_4321
    _W129 = (1 << 128) | (0xDEAD_BEEF_CAFE_BABE << 32) | 0x1234_5678

    @staticmethod
    def _combo(mod: Module, drives: dict, output: str = "y") -> tuple:
        """Run mod with vm and compiled, return (vm_result, compiled_result)."""
        results = {}
        for eng in ["vm", "compiled"]:
            sim = Simulator(mod, engine=eng)
            for name, val in drives.items():
                sim.drive(name, val)
            sim.run(max_time=0)
            results[eng] = sim.read(output)
        return results["vm"], results["compiled"]

    @staticmethod
    def _seq(mod: Module, drives: dict, output: str = "q") -> tuple:
        """Run clocked mod one cycle (posedge), return (vm_result, compiled_result)."""
        results = {}
        for eng in ["vm", "compiled"]:
            sim = Simulator(mod, engine=eng)
            for name, val in drives.items():
                sim.drive(name, val)
            clk = Clock(sim.signal("clk"), period=10)
            sim.fork(clk)
            sim._schedule_clock_events(clk, 40)
            for _ in range(2):
                sim.run_step()
            results[eng] = sim.read(output)
        return results["vm"], results["compiled"]

    # ── Continuous-assign operators ───────────────────────────────────────

    @pytest.mark.parametrize("width", [65, 129])
    def test_cont_add_cross_engine(self, width):
        a = self._W65 if width == 65 else self._W129
        b = self._W65b if width == 65 else (self._W129 >> 3)
        vm, comp = self._combo(
            _make_wide_cont_add(width),
            {"a": Value(a, width=width), "b": Value(b, width=width)},
        )
        assert comp == vm
        mask = (1 << width) - 1
        assert vm == Value((a + b) & mask, width=width)

    @pytest.mark.parametrize(
        "op,out_name,py_op",
        [
            ("&", "y_and", lambda a, b: a & b),
            ("|", "y_or", lambda a, b: a | b),
            ("^", "y_xor", lambda a, b: a ^ b),
        ],
    )
    def test_cont_bitwise_cross_engine(self, op, out_name, py_op):
        width = 65
        a, b = self._W65, self._W65b
        vm, comp = self._combo(
            _make_wide_cont_multi_bitwise(width),
            {"a": Value(a, width=width), "b": Value(b, width=width)},
            output=out_name,
        )
        assert comp == vm
        mask = (1 << width) - 1
        assert vm == Value(py_op(a, b) & mask, width=width)

    def test_cont_not_cross_engine(self):
        width = 65
        a = self._W65
        vm, comp = self._combo(
            _make_wide_cont_not(width),
            {"a": Value(a, width=width)},
        )
        assert comp == vm
        mask = (1 << width) - 1
        assert vm == Value((~a) & mask, width=width)

    @pytest.mark.parametrize("width", [65, 129])
    def test_cont_equality_cross_engine(self, width):
        a = self._W65 if width == 65 else self._W129
        b = self._W65b if width == 65 else self._W129  # b == a for 129-bit
        vm_ne, comp_ne = self._combo(
            _make_wide_equality(width),
            {"a": Value(a, width=width), "b": Value(b, width=width)},
        )
        assert comp_ne == vm_ne
        # Equal case
        vm_eq, comp_eq = self._combo(
            _make_wide_equality(width),
            {"a": Value(a, width=width), "b": Value(a, width=width)},
        )
        assert comp_eq == vm_eq
        assert vm_eq == Value(1, width=1)

    @pytest.mark.parametrize("width", [65, 129])
    def test_cont_lt_cross_engine(self, width):
        a = self._W65 if width == 65 else self._W129
        b = self._W65b if width == 65 else (self._W129 >> 1)
        vm, comp = self._combo(
            _make_wide_cont_lt(width),
            {"a": Value(a, width=width), "b": Value(b, width=width)},
        )
        assert comp == vm
        assert vm == Value(1 if a < b else 0, width=1)

    # ── Always-block operators (blocking assign) ──────────────────────────

    @pytest.mark.parametrize("width", [65, 129])
    def test_combo_add_cross_engine(self, width):
        a = self._W65 if width == 65 else self._W129
        b = self._W65b if width == 65 else (self._W129 >> 3)
        vm, comp = self._combo(
            _make_wide_combo_add(width),
            {"a": Value(a, width=width), "b": Value(b, width=width)},
        )
        assert comp == vm
        mask = (1 << width) - 1
        assert vm == Value((a + b) & mask, width=width)

    @pytest.mark.parametrize("op,out_name", [("&", "y_and"), ("|", "y_or"), ("^", "y_xor")])
    def test_combo_bitwise_cross_engine(self, op, out_name):
        width = 65
        a, b = self._W65, self._W65b
        vm, comp = self._combo(
            _make_wide_combo_multi_bitwise(width),
            {"a": Value(a, width=width), "b": Value(b, width=width)},
            output=out_name,
        )
        assert comp == vm

    def test_combo_sub_cross_engine(self):
        width = 65
        a, b = self._W65, self._W65b
        vm, comp = self._combo(
            _make_wide_combo_sub(width),
            {"a": Value(a, width=width), "b": Value(b, width=width)},
        )
        assert comp == vm
        mask = (1 << width) - 1
        assert vm == Value((a - b) & mask, width=width)

    # ── Sequential operators (NBA) ────────────────────────────────────────

    @pytest.mark.parametrize("width", [65, 129])
    def test_seq_add_cross_engine(self, width):
        a = self._W65 if width == 65 else self._W129
        b = self._W65b if width == 65 else (self._W129 >> 3)
        vm, comp = self._seq(
            _make_wide_seq_add(width),
            {"a": Value(a, width=width), "b": Value(b, width=width), "q": Value(0, width=width)},
        )
        assert comp == vm
        mask = (1 << width) - 1
        assert vm == Value((a + b) & mask, width=width)

    @pytest.mark.parametrize("op,out_name", [("&", "q_and"), ("|", "q_or"), ("^", "q_xor")])
    def test_seq_bitwise_cross_engine(self, op, out_name):
        width = 65
        a, b = self._W65, self._W65b
        vm, comp = self._seq(
            _make_wide_seq_multi_bitwise(width),
            {
                "a": Value(a, width=width),
                "b": Value(b, width=width),
                "q_and": Value(0, width=width),
                "q_or": Value(0, width=width),
                "q_xor": Value(0, width=width),
            },
            output=out_name,
        )
        assert comp == vm

    # ── Phase 2.1: struct field reads as wide subexpressions ─────────────

    @pytest.mark.parametrize(
        "op,out_name,py_op",
        [
            ("&", "y_and", lambda a, b: a & b),
            ("|", "y_or", lambda a, b: a | b),
            ("^", "y_xor", lambda a, b: a ^ b),
        ],
    )
    def test_cont_struct_field_binop_cross_engine(self, op, out_name, py_op):
        """Struct signal field reads in a compound expr: assign y = bus_a.data <op> bus_b.data."""
        data_width = 65
        total_width = data_width + 1  # valid at bit 0, data at bits [65:1]
        data_a, data_b = self._W65, self._W65b
        packed_a = (data_a << 1) | 1  # valid=1
        packed_b = (data_b << 1) | 0  # valid=0
        vm, comp = self._combo(
            _make_wide_struct_field_multi_binop(),
            {
                "in_a": Value(packed_a, width=total_width),
                "in_b": Value(packed_b, width=total_width),
            },
            output=out_name,
        )
        assert comp == vm
        mask = (1 << data_width) - 1
        assert vm == Value(py_op(data_a, data_b) & mask, width=data_width)

    @pytest.mark.parametrize(
        "op,out_name,py_op",
        [
            ("&", "y_and", lambda a, b: a & b),
            ("|", "y_or", lambda a, b: a | b),
            ("^", "y_xor", lambda a, b: a ^ b),
        ],
    )
    def test_cont_struct_mem_field_binop_cross_engine(self, op, out_name, py_op):
        """Memory element struct field reads in a compound expr: assign y = mem[0].data <op> mem[1].data."""
        data_width = 65
        total_width = data_width + 1  # valid at bit 0, data at bits [65:1]
        data_a, data_b = self._W65, self._W65b
        packed_a = (data_a << 1) | 1  # valid=1
        packed_b = (data_b << 1) | 0  # valid=0
        vm, comp = self._combo(
            _make_wide_struct_mem_field_multi_binop(),
            {
                "in_a": Value(packed_a, width=total_width),
                "in_b": Value(packed_b, width=total_width),
            },
            output=out_name,
        )
        assert comp == vm
        mask = (1 << data_width) - 1
        assert vm == Value(py_op(data_a, data_b) & mask, width=data_width)

    # ── Phase 3: multiply, divide, modulo, signed comparisons ─────────────

    @pytest.mark.parametrize("width", [65, 129])
    def test_cont_mul_cross_engine(self, width):
        a = self._W65 if width == 65 else self._W129
        b = self._W65b if width == 65 else (self._W129 >> 3)
        vm, comp = self._combo(
            _make_wide_cont_mul(width),
            {"a": Value(a, width=width), "b": Value(b, width=width)},
        )
        assert comp == vm
        mask = (1 << width) - 1
        assert vm == Value((a * b) & mask, width=width)

    @pytest.mark.parametrize("op,py_op", [("/", lambda a, b: a // b), ("%", lambda a, b: a % b)])
    def test_cont_divmod_cross_engine(self, op, py_op):
        width = 65
        a_val = self._W65b  # positive 65-bit: bit64=0, about 9.2e18
        b_val = 0xDEAD_BEEF_CAFE  # about 2.4e13 (fits in 44 bits)
        mask = (1 << width) - 1
        vm, comp = self._combo(
            _make_wide_cont_divmod(width, op),
            {"a": Value(a_val, width=width), "b": Value(b_val, width=width)},
        )
        assert comp == vm
        assert vm == Value(py_op(a_val, b_val) & mask, width=width)

    @pytest.mark.parametrize("width", [65, 129])
    def test_cont_div_zero_divisor_returns_x(self, width):
        """Per Verilog spec: division by zero returns X (all bits unknown)."""
        a_val = self._W65 if width == 65 else self._W129
        vm, comp = self._combo(
            _make_wide_cont_divmod(width, "/"),
            {"a": Value(a_val, width=width), "b": Value(0, width=width)},
        )
        assert comp == vm
        assert vm == Value.x(width), f"divide by zero: expected all-X, got {vm}"

    @pytest.mark.parametrize("width", [65, 129])
    def test_cont_mod_zero_divisor_returns_x(self, width):
        """Per Verilog spec: modulo by zero returns X (all bits unknown)."""
        a_val = self._W65b if width == 65 else (self._W129 >> 3)
        vm, comp = self._combo(
            _make_wide_cont_divmod(width, "%"),
            {"a": Value(a_val, width=width), "b": Value(0, width=width)},
        )
        assert comp == vm
        assert vm == Value.x(width), f"modulo by zero: expected all-X, got {vm}"

    @pytest.mark.parametrize(
        "op,out_name,py_op",
        [
            ("<", "y_lt", lambda a, b: int(a < b)),
            ("<=", "y_le", lambda a, b: int(a <= b)),
            (">", "y_gt", lambda a, b: int(a > b)),
            (">=", "y_ge", lambda a, b: int(a >= b)),
        ],
    )
    def test_cont_signed_cmp_cross_engine(self, op, out_name, py_op):
        """Signed comparison: _W65 has sign bit set (negative), _W65b does not (positive)."""
        width = 65
        a_val = self._W65  # bit 64 = 1 → negative as signed 65-bit
        b_val = self._W65b  # bit 64 = 0 → positive as signed 65-bit
        sign_bit = 1 << (width - 1)

        def to_signed(v: int) -> int:
            return v - (1 << width) if v >= sign_bit else v

        sa, sb = to_signed(a_val), to_signed(b_val)
        vm, comp = self._combo(
            _make_wide_cont_multi_signed_cmp(width),
            {"a": Value(a_val, width=width), "b": Value(b_val, width=width)},
            output=out_name,
        )
        assert comp == vm
        assert vm == Value(py_op(sa, sb), width=1)


# ─── Phase 4 module factories ────────────────────────────────────────────────


def _make_wide_combo_dyn_shift(width: int, op: str) -> Module:
    """always @(*) y = a >> shamt; wide signal, signal-valued shift amount."""
    op_tag = {"<<": "shl", ">>": "shr", ">>>": "ashr"}[op]
    shamt_width = max(1, (width - 1).bit_length())
    mod = Module(
        f"wide_combo_dyn_{op_tag}_{width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("shamt", PortDirection.INPUT, width=_w(shamt_width)),
            Port("y", PortDirection.OUTPUT, width=_w(width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("shamt", NetKind.WIRE, width=_w(shamt_width)),
        ],
        variables=[Variable("y", VariableKind.REG, width=_w(width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(Identifier("y"), BinaryOp(op, Identifier("a"), Identifier("shamt"))),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        )
    ]
    return mod


def _make_wide_seq_dyn_shift(width: int, op: str) -> Module:
    """always @(posedge clk) q <= a >> shamt; wide signal, signal-valued shift amount."""
    op_tag = {"<<": "shl", ">>": "shr", ">>>": "ashr"}[op]
    shamt_width = max(1, (width - 1).bit_length())
    mod = Module(
        f"wide_seq_dyn_{op_tag}_{width}",
        ports=[
            Port("clk", PortDirection.INPUT),
            Port("a", PortDirection.INPUT, width=_w(width)),
            Port("shamt", PortDirection.INPUT, width=_w(shamt_width)),
            Port("q", PortDirection.OUTPUT, width=_w(width)),
        ],
        nets=[
            Net("clk", NetKind.WIRE),
            Net("a", NetKind.WIRE, width=_w(width)),
            Net("shamt", NetKind.WIRE, width=_w(shamt_width)),
        ],
        variables=[Variable("q", VariableKind.REG, width=_w(width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            NonblockingAssign(Identifier("q"), BinaryOp(op, Identifier("a"), Identifier("shamt"))),
            sensitivity_list=[SensitivityEdge("posedge", Identifier("clk"))],
            sensitivity_type=SensitivityType.SEQUENTIAL,
        )
    ]
    return mod


def _make_wide_combo_dyn_part_select(src_width: int, slice_width: int) -> Module:
    """always @(*) y = a[base +: slice_width]; dynamic part-select on wide source."""
    shamt_width = max(1, (src_width - 1).bit_length())
    mod = Module(
        f"wide_combo_dyn_ps_{src_width}_{slice_width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("base", PortDirection.INPUT, width=_w(shamt_width)),
            Port("y", PortDirection.OUTPUT, width=_w(slice_width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("base", NetKind.WIRE, width=_w(shamt_width)),
        ],
        variables=[Variable("y", VariableKind.REG, width=_w(slice_width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(
                Identifier("y"),
                PartSelect(Identifier("a"), Identifier("base"), Literal(slice_width, width=32), "+:"),
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        )
    ]
    return mod


def _make_wide_combo_dyn_range_select(src_width: int, slice_width: int) -> Module:
    """always @(*) y = a[lsb+sw-1:lsb]; dynamic range-select on wide source (both bounds dynamic)."""
    shamt_width = max(1, (src_width - 1).bit_length())
    sw = slice_width
    mod = Module(
        f"wide_combo_dyn_rs_{src_width}_{slice_width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("lsb", PortDirection.INPUT, width=_w(shamt_width)),
            Port("y", PortDirection.OUTPUT, width=_w(slice_width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("lsb", NetKind.WIRE, width=_w(shamt_width)),
        ],
        variables=[Variable("y", VariableKind.REG, width=_w(slice_width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(
                Identifier("y"),
                RangeSelect(
                    Identifier("a"),
                    BinaryOp("+", Identifier("lsb"), Literal(sw - 1, width=32)),  # msb = lsb + sw - 1
                    Identifier("lsb"),
                ),
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        )
    ]
    return mod


def _make_wide_combo_dyn_part_select_subexpr(src_width: int, slice_width: int) -> Module:
    """always @(*) y = (a[base +: slice_width]) & b; dynamic part-select as compound subexpr."""
    shamt_width = max(1, (src_width - 1).bit_length())
    mod = Module(
        f"wide_combo_dyn_ps_subexpr_{src_width}_{slice_width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("b", PortDirection.INPUT, width=_w(slice_width)),
            Port("base", PortDirection.INPUT, width=_w(shamt_width)),
            Port("y", PortDirection.OUTPUT, width=_w(slice_width)),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("b", NetKind.WIRE, width=_w(slice_width)),
            Net("base", NetKind.WIRE, width=_w(shamt_width)),
        ],
        variables=[Variable("y", VariableKind.REG, width=_w(slice_width))],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(
                Identifier("y"),
                BinaryOp(
                    "&",
                    PartSelect(Identifier("a"), Identifier("base"), Literal(slice_width, width=32), "+:"),
                    Identifier("b"),
                ),
            ),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        )
    ]
    return mod


class TestWideDynamicPhase4:
    """Phase 4 behavioral cross-validation: dynamic shift amounts and runtime slice selects.

    Verifies that compiled engine matches vm engine when shift amounts and part-select
    bases are signals rather than compile-time constants.
    """

    _W65 = (1 << 64) | 0x1234_5678_9ABC_DEF0
    _W65b = (1 << 63) | 0x0FED_CBA9_8765_4321
    _W129 = (1 << 128) | (0xDEAD_BEEF_CAFE_BABE << 32) | 0x1234_5678

    @staticmethod
    def _combo(mod: Module, drives: dict, output: str = "y") -> tuple:
        results = {}
        for eng in ["vm", "compiled"]:
            sim = Simulator(mod, engine=eng)
            for name, val in drives.items():
                sim.drive(name, val)
            sim.run(max_time=0)
            results[eng] = sim.read(output)
        return results["vm"], results["compiled"]

    @staticmethod
    def _seq(mod: Module, drives: dict, output: str = "q") -> tuple:
        results = {}
        for eng in ["vm", "compiled"]:
            sim = Simulator(mod, engine=eng)
            for name, val in drives.items():
                sim.drive(name, val)
            clk = Clock(sim.signal("clk"), period=10)
            sim.fork(clk)
            sim._schedule_clock_events(clk, 40)
            for _ in range(2):
                sim.run_step()
            results[eng] = sim.read(output)
        return results["vm"], results["compiled"]

    # ── 4.1 Dynamic shift amount ──────────────────────────────────────────

    @pytest.mark.parametrize(
        "op,shamt",
        [
            (">>", 0),
            (">>", 4),
            (">>", 33),
            (">>", 64),
            ("<<", 0),
            ("<<", 4),
            ("<<", 33),
            ("<<", 64),
            (">>>", 4),
            (">>>", 33),
        ],
    )
    def test_combo_dyn_shift_cross_engine(self, op, shamt):
        width = 65
        a_val = self._W65
        vm, comp = self._combo(
            _make_wide_combo_dyn_shift(width, op),
            {"a": Value(a_val, width=width), "shamt": Value(shamt, width=7)},
        )
        assert comp == vm

    @pytest.mark.parametrize("op,shamt", [(">>", 4), ("<<", 8), (">>>", 16)])
    def test_seq_dyn_shift_cross_engine(self, op, shamt):
        width = 65
        a_val = self._W65
        vm, comp = self._seq(
            _make_wide_seq_dyn_shift(width, op),
            {"a": Value(a_val, width=width), "shamt": Value(shamt, width=7), "q": Value(0, width=width)},
        )
        assert comp == vm

    # ── 4.2 Dynamic part-select (wide LHS, dynamic base) ─────────────────

    @pytest.mark.parametrize("base", [0, 4, 32, 64])
    def test_combo_dyn_part_select_wide_lhs_cross_engine(self, base):
        """y = a[base +: 65] where a is 129-bit: wide result from dynamic PartSelect."""
        src_width, slice_width = 129, 65
        a_val = self._W129
        vm, comp = self._combo(
            _make_wide_combo_dyn_part_select(src_width, slice_width),
            {"a": Value(a_val, width=src_width), "base": Value(base, width=7)},
        )
        assert comp == vm
        expected = (a_val >> base) & ((1 << slice_width) - 1)
        assert vm == Value(expected, width=slice_width)

    @pytest.mark.parametrize("base", [0, 4, 32, 64])
    def test_combo_dyn_part_select_as_subexpr_cross_engine(self, base):
        """y = (a[base +: 65]) & b — dynamic part-select inside compound expression."""
        src_width, slice_width = 129, 65
        a_val, b_val = self._W129, self._W65
        vm, comp = self._combo(
            _make_wide_combo_dyn_part_select_subexpr(src_width, slice_width),
            {
                "a": Value(a_val, width=src_width),
                "b": Value(b_val, width=slice_width),
                "base": Value(base, width=7),
            },
        )
        assert comp == vm
        slice_val = (a_val >> base) & ((1 << slice_width) - 1)
        assert vm == Value(slice_val & b_val & ((1 << slice_width) - 1), width=slice_width)

    # ── 4.3 Dynamic range-select ──────────────────────────────────────────

    @pytest.mark.parametrize("lsb", [0, 4, 32, 64])
    def test_combo_dyn_range_select_wide_lhs_cross_engine(self, lsb):
        """y = a[lsb+64:lsb] where a is 129-bit: dynamic range-select, wide result."""
        src_width, slice_width = 129, 65
        a_val = self._W129
        vm, comp = self._combo(
            _make_wide_combo_dyn_range_select(src_width, slice_width),
            {"a": Value(a_val, width=src_width), "lsb": Value(lsb, width=7)},
        )
        assert comp == vm
        expected = (a_val >> lsb) & ((1 << slice_width) - 1)
        assert vm == Value(expected, width=slice_width)


# ── Wide logical operators: !, &&, || on wide operands ───────────────────────


class TestWideLogicalOps:
    """Logical operators on wide (>64-bit) signals must read all words correctly.

    The critical regression: if only the high word is nonzero (e.g. a=2**64),
    the old scalar path read c.val[sid]==0 and returned wrong results.
    """

    ENGINES = ["vm", "vm-fast", "compiled"]  # noqa: RUF012
    W = 65  # 65-bit operands: one bit beyond the first word

    # a value with only the 65th bit set — low 64 bits are zero
    HIGH_BIT = 1 << 64

    @staticmethod
    def _run(mod, inputs):
        results = {}
        for eng in ["vm", "compiled"]:
            sim = Simulator(mod, engine=eng)
            for name, val in inputs.items():
                sim.drive(name, val)
            sim.run(max_time=0)
            results[eng] = sim.read("y")
        return results["vm"], results["compiled"]

    # ── logical NOT ──────────────────────────────────────────────────────────

    def test_logical_not_zero_input(self):
        """!0 == 1 for wide zero."""
        vm, comp = self._run(_make_wide_logical_not(self.W), {"a": Value(0, width=self.W)})
        assert comp == vm
        assert vm == Value(1, width=1)

    def test_logical_not_low_bit_set(self):
        """!1 == 0 (nonzero in low word)."""
        vm, comp = self._run(_make_wide_logical_not(self.W), {"a": Value(1, width=self.W)})
        assert comp == vm
        assert vm == Value(0, width=1)

    def test_logical_not_high_bit_only(self):
        """!a == 0 when only the 65th bit is set — scalar path bug regression."""
        vm, comp = self._run(
            _make_wide_logical_not(self.W),
            {"a": Value(self.HIGH_BIT, width=self.W)},
        )
        assert comp == vm
        assert vm == Value(0, width=1)

    # ── logical AND ──────────────────────────────────────────────────────────

    def test_logical_and_both_nonzero(self):
        """a && b == 1 when both operands are nonzero (value in high word)."""
        vm, comp = self._run(
            _make_wide_logical_and(self.W),
            {"a": Value(self.HIGH_BIT, width=self.W), "b": Value(1, width=self.W)},
        )
        assert comp == vm
        assert vm == Value(1, width=1)

    def test_logical_and_one_zero(self):
        """a && b == 0 when a is zero (even though b is nonzero in high word)."""
        vm, comp = self._run(
            _make_wide_logical_and(self.W),
            {"a": Value(0, width=self.W), "b": Value(self.HIGH_BIT, width=self.W)},
        )
        assert comp == vm
        assert vm == Value(0, width=1)

    def test_logical_and_both_high_bits(self):
        """a && b == 1 when both have only the high bit set."""
        vm, comp = self._run(
            _make_wide_logical_and(self.W),
            {"a": Value(self.HIGH_BIT, width=self.W), "b": Value(self.HIGH_BIT, width=self.W)},
        )
        assert comp == vm
        assert vm == Value(1, width=1)

    # ── logical OR ───────────────────────────────────────────────────────────

    def test_logical_or_both_zero(self):
        """a || b == 0 when both operands are zero."""
        vm, comp = self._run(
            _make_wide_logical_or(self.W),
            {"a": Value(0, width=self.W), "b": Value(0, width=self.W)},
        )
        assert comp == vm
        assert vm == Value(0, width=1)

    def test_logical_or_one_high_bit(self):
        """a || b == 1 when only 'a' has the 65th bit set — scalar path bug regression."""
        vm, comp = self._run(
            _make_wide_logical_or(self.W),
            {"a": Value(self.HIGH_BIT, width=self.W), "b": Value(0, width=self.W)},
        )
        assert comp == vm
        assert vm == Value(1, width=1)

    def test_logical_or_only_b_nonzero(self):
        """a || b == 1 when only 'b' is nonzero in high word."""
        vm, comp = self._run(
            _make_wide_logical_or(self.W),
            {"a": Value(0, width=self.W), "b": Value(self.HIGH_BIT, width=self.W)},
        )
        assert comp == vm
        assert vm == Value(1, width=1)


# ── Fail-fast: unsupported constructs raise at codegen time ──────────────────


def _make_wide_logical_not(src_width: int) -> Module:
    """y = !a; where a is wide and y is 1-bit."""
    mod = Module(
        f"wide_logical_not_{src_width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("y", PortDirection.OUTPUT),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(src_width)),
        ],
        variables=[Variable("y", VariableKind.REG)],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(Identifier("y"), UnaryOp("!", Identifier("a"))),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        ),
    ]
    return mod


def _make_wide_logical_and(src_width: int) -> Module:
    """y = a && b; where a, b are wide and y is 1-bit."""
    mod = Module(
        f"wide_logical_and_{src_width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("b", PortDirection.INPUT, width=_w(src_width)),
            Port("y", PortDirection.OUTPUT),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("b", NetKind.WIRE, width=_w(src_width)),
        ],
        variables=[Variable("y", VariableKind.REG)],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(Identifier("y"), BinaryOp("&&", Identifier("a"), Identifier("b"))),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        ),
    ]
    return mod


def _make_wide_logical_or(src_width: int) -> Module:
    """y = a || b; where a, b are wide and y is 1-bit."""
    mod = Module(
        f"wide_logical_or_{src_width}",
        ports=[
            Port("a", PortDirection.INPUT, width=_w(src_width)),
            Port("b", PortDirection.INPUT, width=_w(src_width)),
            Port("y", PortDirection.OUTPUT),
        ],
        nets=[
            Net("a", NetKind.WIRE, width=_w(src_width)),
            Net("b", NetKind.WIRE, width=_w(src_width)),
        ],
        variables=[Variable("y", VariableKind.REG)],
    )
    mod.always_blocks = [
        AlwaysBlock(
            BlockingAssign(Identifier("y"), BinaryOp("||", Identifier("a"), Identifier("b"))),
            sensitivity_type=SensitivityType.COMBINATIONAL,
        ),
    ]
    return mod


def _make_module_with_stmt(stmt) -> Module:
    """Helper: minimal module whose always_comb body is a single statement."""
    from veriforge.model.behavioral import SensitivityType

    mod = Module(
        "fail_fast_test",
        ports=[Port("y", PortDirection.OUTPUT, width=_w8())],
        nets=[],
        variables=[Variable("y", VariableKind.REG, width=_w8())],
    )
    mod.always_blocks = [AlwaysBlock(SeqBlock([stmt]), sensitivity_type=SensitivityType.COMBINATIONAL)]
    return mod


class TestCompiledFailFast:
    """Unsupported compiled constructs must raise NotImplementedError at codegen time."""

    def _codegen(self, mod: Module) -> None:
        CythonCodegen().generate(mod)

    def test_unsupported_statement_type_raises(self):
        """ParBlock (fork...join) is unsupported — must raise, not emit pass."""
        from veriforge.model.statements import ParBlock

        stmt = ParBlock([BlockingAssign(Identifier("y"), Literal(0, width=8))])
        with pytest.raises(NotImplementedError, match="ParBlock"):
            self._codegen(_make_module_with_stmt(stmt))

    def test_wait_statement_routes_to_fallback(self):
        """WaitStatement triggers the timing-fallback path (block is skipped, not compiled)."""
        from veriforge.model.statements import WaitStatement

        # A block containing WaitStatement has _has_timing == True, so the compiled
        # engine routes it to the reference executor fallback rather than raising.
        # Verify that codegen succeeds (no raise) and the block is silently excluded.
        stmt = WaitStatement(Literal(1, width=1))
        mod = _make_module_with_stmt(stmt)
        code = CythonCodegen().generate(mod)
        # The generated code should have no reference to the wait condition
        # (the block was skipped, not compiled).
        assert "wait" not in code.lower().split("def ")[0]  # not in the module header area

    def test_disable_statement_raises(self):
        """DisableStatement is unsupported — must raise, not emit pass."""
        from veriforge.model.statements import DisableStatement

        stmt = DisableStatement("some_block")
        with pytest.raises(NotImplementedError, match="DisableStatement"):
            self._codegen(_make_module_with_stmt(stmt))

    def test_event_trigger_raises(self):
        """EventTrigger is unsupported — must raise, not emit pass."""
        from veriforge.model.statements import EventTrigger

        stmt = EventTrigger("my_event")
        with pytest.raises(NotImplementedError, match="EventTrigger"):
            self._codegen(_make_module_with_stmt(stmt))

    def test_unresolved_lhs_identifier_raises(self):
        """BlockingAssign to an unknown identifier must raise, not emit pass."""
        stmt = BlockingAssign(Identifier("nonexistent_signal"), Literal(0, width=8))
        with pytest.raises(NotImplementedError, match="nonexistent_signal"):
            self._codegen(_make_module_with_stmt(stmt))

    def test_unresolved_bitselect_target_raises(self):
        """Bit-select on unknown signal must raise, not emit pass."""
        stmt = BlockingAssign(BitSelect(Identifier("nonexistent"), Literal(0, width=8)), Literal(0, width=1))
        with pytest.raises(NotImplementedError, match="nonexistent"):
            self._codegen(_make_module_with_stmt(stmt))

    def test_unresolved_range_select_target_raises(self):
        """Range-select on unknown signal must raise, not emit pass."""
        stmt = BlockingAssign(
            RangeSelect(Identifier("nonexistent"), Literal(7, width=8), Literal(0, width=8)),
            Literal(0, width=8),
        )
        with pytest.raises(NotImplementedError, match="nonexistent"):
            self._codegen(_make_module_with_stmt(stmt))


# ── Work package 1.4: Timing diagnostics ─────────────────────────────────────


def _make_always_clk_gen() -> Module:
    """always #5 clk = ~clk; — canonical slow clock-generator pattern."""
    mod = Module(
        "clk_gen",
        ports=[Port("clk", PortDirection.OUTPUT)],
        nets=[Net("clk", NetKind.WIRE)],
    )
    mod.always_blocks = [
        AlwaysBlock(
            ForeverLoop(
                SeqBlock(
                    [
                        DelayControl(Literal(5, width=32)),
                        BlockingAssign(Identifier("clk"), UnaryOp("~", Identifier("clk"))),
                    ]
                )
            ),
            sensitivity_list=[],
        )
    ]
    return mod


def _make_always_event_control() -> Module:
    """always @(posedge trigger) y = ~y; — always block with event control."""
    from veriforge.model.statements import EventControl

    mod = Module(
        "event_ctrl",
        ports=[
            Port("trigger", PortDirection.INPUT),
            Port("y", PortDirection.OUTPUT),
        ],
        nets=[Net("trigger", NetKind.WIRE)],
        variables=[Variable("y", VariableKind.REG)],
    )
    mod.always_blocks = [
        AlwaysBlock(
            SeqBlock(
                [
                    EventControl(
                        events=[SensitivityEdge("posedge", Identifier("trigger"))],
                        body=BlockingAssign(Identifier("y"), UnaryOp("~", Identifier("y"))),
                    ),
                ]
            ),
            sensitivity_list=[],
        )
    ]
    return mod


def _make_initial_timing_single_delay() -> Module:
    """initial #10 y = 1; — initial block with a single delay."""
    mod = Module(
        "init_timing_delay",
        ports=[Port("y", PortDirection.OUTPUT)],
        variables=[Variable("y", VariableKind.REG)],
    )
    mod.initial_blocks = [
        InitialBlock(
            SeqBlock(
                [
                    DelayControl(Literal(10, width=32)),
                    BlockingAssign(Identifier("y"), Literal(1, width=1)),
                ]
            )
        )
    ]
    return mod


def _make_initial_timing_delay_loop() -> Module:
    """initial while(1) begin #10 clk = ~clk; end — slow timing loop."""
    mod = Module(
        "init_timing_delay_loop",
        ports=[Port("clk", PortDirection.OUTPUT)],
        variables=[Variable("clk", VariableKind.REG)],
    )
    mod.initial_blocks = [
        InitialBlock(
            WhileLoop(
                Literal(1, width=1),
                SeqBlock(
                    [
                        DelayControl(Literal(10, width=32)),
                        BlockingAssign(Identifier("clk"), UnaryOp("~", Identifier("clk"))),
                    ]
                ),
            )
        )
    ]
    return mod


class TestTimingDiagnostics:
    """Compiled engine emits timing performance warnings for slow patterns."""

    @staticmethod
    def _diags(mod: Module) -> list[str]:
        cg = CythonCodegen()
        cg.generate(mod)
        return cg.timing_diagnostics

    def test_no_diagnostics_for_clean_module(self):
        """Module with no timing controls produces no timing diagnostics."""
        assert self._diags(_make_adder()) == []

    def test_no_diagnostics_for_sequential_module(self):
        """Module with only posedge always blocks produces no timing diagnostics."""
        assert self._diags(_make_counter()) == []

    def test_clock_gen_always_produces_diagnostic(self):
        """always #N loop (clock generator) triggers a timing diagnostic."""
        diags = self._diags(_make_always_clk_gen())
        assert len(diags) == 1
        assert "batch_run" in diags[0]

    def test_clock_gen_diagnostic_mentions_delay_loop(self):
        """Clock-generator diagnostic mentions #delay loop pattern."""
        diags = self._diags(_make_always_clk_gen())
        assert "#delay" in diags[0]

    def test_always_event_control_produces_diagnostic(self):
        """always block with @event control triggers a timing diagnostic."""
        diags = self._diags(_make_always_event_control())
        assert len(diags) == 1
        assert "timing control" in diags[0]

    def test_initial_single_delay_produces_diagnostic(self):
        """initial block with a single #delay triggers a timing diagnostic."""
        diags = self._diags(_make_initial_timing_single_delay())
        assert len(diags) == 1
        assert "#delay" in diags[0]

    def test_initial_delay_loop_produces_loop_diagnostic(self):
        """initial block with a timing loop triggers the loop-specific diagnostic."""
        diags = self._diags(_make_initial_timing_delay_loop())
        assert len(diags) == 1
        assert "loop" in diags[0]
        assert "batch_run" in diags[0]

    def test_multiple_slow_blocks_produce_multiple_diagnostics(self):
        """Two slow always blocks produce two separate diagnostics."""
        mod = _make_always_clk_gen()
        # Add a second always-with-timing block
        second = AlwaysBlock(
            ForeverLoop(
                SeqBlock(
                    [
                        DelayControl(Literal(3, width=32)),
                        BlockingAssign(Identifier("clk"), Literal(0, width=1)),
                    ]
                )
            ),
            sensitivity_list=[],
        )
        mod.always_blocks.append(second)
        diags = self._diags(mod)
        assert len(diags) == 2

    def test_timing_diagnostics_empty_before_generate(self):
        """CythonCodegen.timing_diagnostics is empty before generate() is called."""
        cg = CythonCodegen()
        assert cg.timing_diagnostics == []

    def test_diagnostic_includes_per_process_number(self):
        """Each diagnostic message names the process number (always/initial block N)."""
        diags = self._diags(_make_always_clk_gen())
        assert "always block 1" in diags[0]

    def test_multiple_blocks_numbered_separately(self):
        """Two falling-back always blocks get distinct numbers."""
        mod = _make_always_clk_gen()
        mod.always_blocks.append(
            AlwaysBlock(
                ForeverLoop(
                    SeqBlock(
                        [
                            DelayControl(Literal(3, width=32)),
                            BlockingAssign(Identifier("clk"), Literal(0, width=1)),
                        ]
                    )
                ),
                sensitivity_list=[],
            )
        )
        diags = self._diags(mod)
        assert len(diags) == 2
        assert "always block 1" in diags[0]
        assert "always block 2" in diags[1]

    def test_diagnostic_includes_cost_estimate(self):
        """Diagnostics include the '10–100×' performance cost language."""
        diags = self._diags(_make_always_clk_gen())
        assert "10" in diags[0] and "100" in diags[0]

    def test_initial_system_task_produces_diagnostic(self):
        """initial block with only $display (no timing) also triggers a diagnostic."""
        mod = Module(
            "init_systask",
            ports=[Port("y", PortDirection.OUTPUT)],
            variables=[Variable("y", VariableKind.REG)],
        )
        mod.initial_blocks = [
            InitialBlock(
                SeqBlock(
                    [
                        SystemTaskCall("$display", [StringLiteral("hello")]),
                        BlockingAssign(Identifier("y"), Literal(1, width=1)),
                    ]
                )
            )
        ]
        diags = self._diags(mod)
        assert len(diags) == 1
        assert "system task" in diags[0].lower()
        assert "initial block 1" in diags[0]

    def test_initial_system_task_and_timing_combined(self):
        """initial block with both $display and #delay names both reasons."""
        mod = Module(
            "init_both",
            ports=[Port("y", PortDirection.OUTPUT)],
            variables=[Variable("y", VariableKind.REG)],
        )
        mod.initial_blocks = [
            InitialBlock(
                SeqBlock(
                    [
                        SystemTaskCall("$display", [StringLiteral("start")]),
                        DelayControl(Literal(5, width=32)),
                        BlockingAssign(Identifier("y"), Literal(1, width=1)),
                    ]
                )
            )
        ]
        diags = self._diags(mod)
        assert len(diags) == 1
        # Both reasons should appear in the single combined diagnostic
        assert "timing" in diags[0].lower() or "#delay" in diags[0]
        assert "system task" in diags[0].lower()

    def test_preflight_warning_emitted_via_simulator(self):
        """Simulator emits a UserWarning when the compiled engine has timing fallbacks."""
        import warnings as _warnings

        mod = _make_always_clk_gen()
        with _warnings.catch_warnings(record=True) as rec:
            _warnings.simplefilter("always")
            Simulator(mod, engine="compiled")
        user_warnings = [w for w in rec if issubclass(w.category, UserWarning)]
        assert any("preflight" in str(w.message).lower() for w in user_warnings), (
            f"Expected a UserWarning with 'preflight', got: {[str(w.message) for w in user_warnings]}"
        )


